1	import { Node, Prefab, instantiate, NodePool, Vec3, sp, log } from 'cc';
2	
3	/**
4	 * @ch 通用節點物件池管理器
5	 * 
6	 * 功能特色：
7	 * - 基於字符串鍵值的物件池管理
8	 * - 支援 Prefab 和 Node 作為模板
9	 * - 自動節點生命週期管理
10	 * - 提供便捷的節點取得和歸還方法
11	 * - 集中的記憶體管理和除錯功能
12	 * 
13	 * 使用場景：
14	 * - 炸彈效果系統
15	 * - 動態特效管理
16	 * - 可重用的 UI 元件
17	 * - 任何需要頻繁創建/銷毀節點的場景
18	 */
19	export class PrefabPoolManager {
20	    private static instance: PrefabPoolManager = null;
21	    
22	    /**@ch 物件池映射表 */
23	    private m_pools: Map<string, NodePool> = new Map();
24	    
25	    /**@ch 模板映射表（可以是 Prefab 或 Node） */
26	    private m_templates: Map<string, Prefab | Node> = new Map();
27	    
28	    /**@ch 預設池大小 */
29	    private readonly DEFAULT_POOL_SIZE: number = 1;
30	    
31	    /**@ch 是否啟用除錯日誌 */
32	    private m_debugMode: boolean = false;
33	
34	    /** @ch GC 優化：快取節點的 Spine 元件列表，避免每次 get/return 遍歷子樹 */
35	    private m_spineCache: WeakMap<Node, sp.Skeleton[]> = new WeakMap();
36	
37	    private constructor() {
38	        this.m_debugMode = false; // 可以通過外部設定開啟
39	    }
40	
41	    /**@ch 取得單例實例 */
42	    public static GetInstance(): PrefabPoolManager {
43	        if (!PrefabPoolManager.instance) {
44	            PrefabPoolManager.instance = new PrefabPoolManager();
45	        }
46	        return PrefabPoolManager.instance;
47	    }
48	
49	    /**
50	     * @ch GC 優化：取得快取的 Spine 元件列表（首次查詢後快取）
51	     * @param node 目標節點
52	     * @returns Spine 元件陣列
53	     */
54	    private getCachedSpines(node: Node): sp.Skeleton[] {
55	        let spines = this.m_spineCache.get(node);
56	        if (!spines) {
57	            spines = node.getComponentsInChildren(sp.Skeleton);
58	            this.m_spineCache.set(node, spines);
59	        }
60	        return spines;
61	    }
62	
63	    /**
64	     * @ch 註冊模板（支援 Prefab 或 Node）
65	     * @param key 唯一識別鍵
66	     * @param template Prefab 資源或 Node 實例
67	     * @param preCreateCount 預先建立的節點數量（預設 1）
68	     */
69	    public RegisterTemplate(key: string, template: Prefab | Node, preCreateCount: number = this.DEFAULT_POOL_SIZE): void {
70	        if (!key || !template) {
71	            console.error('PrefabPoolManager: Invalid key or template');
72	            return;
73	        }
74	
75	        if (this.m_templates.has(key)) {
76	            console.warn(`PrefabPoolManager: Key '${key}' already exists, overriding...`);
77	        }
78	
79	        // 儲存模板
80	        this.m_templates.set(key, template);
81	
82	        // 建立新的物件池
83	        const pool = new NodePool();
84	        pool.poolHandlerComp = null;
85	
86	        // 預先建立節點到池中
87	        for (let i = 0; i < preCreateCount; i++) {
88	            const node = this.CreateNodeFromTemplate(template);
89	            if (node) {
90	                node.active = false;
91	                pool.put(node);
92	            }
93	        }
94	
95	        this.m_pools.set(key, pool);
96	
97	        if (this.m_debugMode) {
98	            const templateType = template instanceof Prefab ? 'Prefab' : 'Node';
99	            log(`PrefabPoolManager: Registered '${key}' (${templateType}) with ${preCreateCount} pre-created nodes`);
100	        }
101	    }
102	
103	    /**
104	     * @ch 註冊 Prefab 類型（向後兼容）
105	     * @param key 唯一識別鍵
106	     * @param prefab Prefab 資源
107	     * @param preCreateCount 預先建立的節點數量（預設 1）
108	     */
109	    public RegisterPrefab(key: string, prefab: Prefab, preCreateCount: number = this.DEFAULT_POOL_SIZE): void {
110	        this.RegisterTemplate(key, prefab, preCreateCount);
111	    }
112	
113	    /**
114	     * @ch 註冊 Node 類型
115	     * @param key 唯一識別鍵
116	     * @param node Node 實例（將作為模板使用）
117	     * @param preCreateCount 預先建立的節點數量（預設 1）
118	     */
119	    public RegisterNode(key: string, node: Node, preCreateCount: number = this.DEFAULT_POOL_SIZE): void {
120	        this.RegisterTemplate(key, node, preCreateCount);
121	    }
122	
123	    /**
124	     * @ch 從模板創建節點
125	     * @param template Prefab 或 Node 模板
126	     * @returns 新的節點實例
127	     */
128	    private CreateNodeFromTemplate(template: Prefab | Node): Node {
129	        if (template instanceof Prefab) {
130	            return instantiate(template);
131	        } else {
132	            // 如果是 Node，創建一個副本
133	            const clonedNode = instantiate(template);
134	            return clonedNode;
135	        }
136	    }
137	
138	    /**
139	     * @ch 取得節點
140	     * @param key 模板識別鍵
141	     * @param parent 父節點（可選）
142	     * @param position 位置（可選）
143	     * @param scale 縮放（可選）
144	     * @returns 節點實例
145	     */
146	    public GetNode(key: string, parent?: Node, position: Vec3 = Vec3.ZERO, scale: Vec3 = Vec3.ONE): Node {
147	        const pool = this.m_pools.get(key);
148	        const template = this.m_templates.get(key);
149	
150	        if (!pool || !template) {
151	            console.error(`PrefabPoolManager: Key '${key}' not registered. Call RegisterTemplate/RegisterPrefab/RegisterNode first.`);
152	            return null;
153	        }
154	
155	        let node: Node;
156	        
157	        // 嘗試從池中取得節點
158	        if (pool.size() > 0) {
159	            node = pool.get();
160	            if (this.m_debugMode) {
161	                log(`PrefabPoolManager: Retrieved '${key}' from pool (pool size: ${pool.size()})`);
162	            }
163	        } else {
164	            // 池中沒有節點，建立新的
165	            node = this.CreateNodeFromTemplate(template);
166	            if (this.m_debugMode) {
167	                log(`PrefabPoolManager: Created new '${key}' node (pool empty)`);
168	            }
169	        }
170	
171	        // 設定節點屬性
172	        node.active = true;
173	
174	        if (parent) {
175	            node.setParent(parent);
176	        }
177	
178	        if (position) {
179	            node.setPosition(position);
180	        }
181	
182	        if (scale) {
183	            node.setScale(scale);
184	        }
185	
186	        // ⭐ 重新啟用所有 Spine 組件（使用快取避免遍歷子樹）
187	        const spines = this.getCachedSpines(node);
188	        if (spines && spines.length > 0) {
189	            spines.forEach(spine => {
190	                if (spine && !spine.enabled) {
191	                    spine.enabled = true;
192	
193	                    if (this.m_debugMode) {
194	                        log(`PrefabPoolManager: Re-enabled Spine component on '${key}'`);
195	                    }
196	                }
197	            });
198	        }
199	
200	        return node;
201	    }
202	
203	    /**
204	     * @ch 歸還節點到物件池
205	     * @param key 模板識別鍵
206	     * @param node 要歸還的節點
207	     */
208	    public ReturnNode(key: string, node: Node): void {
209	        const pool = this.m_pools.get(key);
210	        
211	        if (!pool) {
212	            console.error(`PrefabPoolManager: Key '${key}' not found, cannot return node`);
213	            return;
214	        }
215	
216	        if (!node || !node.isValid) {
217	            console.warn(`PrefabPoolManager: Invalid node for key '${key}'`);
218	            return;
219	        }
220	
221	        // 重置節點狀態
222	        node.active = false;
223	
224	        // ⭐ 新增：停用所有 Spine 組件（優化版：混合策略）
225	        // 優先處理根節點的 Spine 組件（大多數情況）
226	        const rootSpine = node.getComponent(sp.Skeleton);
227	        if (rootSpine && rootSpine.enabled) {
228	            rootSpine.clearTracks();       // 清除動畫軌道
229	            rootSpine.setToSetupPose();    // 重置為初始姿勢
230	            rootSpine.enabled = false;     // 停用組件
231	
232	            if (this.m_debugMode) {
233	                log(`PrefabPoolManager: Disabled root Spine component on '${key}'`);
234	            }
235	        }
236	
237	        // 只在有子節點時才處理子 Spine（使用快取避免遍歷子樹）
238	        if (node.children.length > 0) {
239	            const childSpines = this.getCachedSpines(node);
240	
241	            childSpines.forEach(spine => {
242	                // 跳過已處理的根節點 Spine
243	                if (spine !== rootSpine && spine.enabled) {
244	                    spine.clearTracks();
245	                    spine.setToSetupPose();
246	                    spine.enabled = false;
247	
248	                    if (this.m_debugMode) {
249	                        log(`PrefabPoolManager: Disabled child Spine component on '${key}'`);
250	                    }
251	                }
252	            });
253	        }
254	
255	        node.removeFromParent();
256	        node.setScale(1, 1, 1);
257	        node.setPosition(0, 0, 0);
258	
259	        // 歸還到池中
260	        pool.put(node);
261	
262	        if (this.m_debugMode) {
263	            log(`PrefabPoolManager: Returned '${key}' to pool (pool size: ${pool.size()})`);
264	        }
265	    }
266	
267	    /**
268	     * @ch 清理特定類型的物件池
269	     * @param key 模板識別鍵
270	     */
271	    public ClearPool(key: string): void {
272	        const pool = this.m_pools.get(key);
273	        
274	        if (!pool) {
275	            console.error(`PrefabPoolManager: Key '${key}' not found`);
276	            return;
277	        }
278	
279	        const oldSize = pool.size();
280	        pool.clear();
281	
282	        if (this.m_debugMode) {
283	            log(`PrefabPoolManager: Cleared pool '${key}' (${oldSize} nodes removed)`);
284	        }
285	    }
286	
287	    /**
288	     * @ch 清理所有物件池
289	     */
290	    public ClearAllPools(): void {
291	        let totalCleared = 0;
292	        
293	        this.m_pools.forEach((pool, key) => {
294	            const size = pool.size();
295	            pool.clear();
296	            totalCleared += size;
297	            
298	            if (this.m_debugMode) {
299	                log(`PrefabPoolManager: Cleared pool '${key}' (${size} nodes)`);
300	            }
301	        });
302	
303	        if (this.m_debugMode) {
304	            log(`PrefabPoolManager: Total ${totalCleared} nodes cleared from all pools`);
305	        }
306	    }
307	
308	    /**
309	     * @ch 取得物件池大小
310	     * @param key 模板識別鍵
311	     * @returns 池中節點數量
312	     */
313	    public GetPoolSize(key: string): number {
314	        const pool = this.m_pools.get(key);
315	        return pool ? pool.size() : 0;
316	    }
317	
318	    /**
319	     * @ch 檢查模板是否已註冊
320	     * @param key 模板識別鍵
321	     * @returns 是否已註冊
322	     */
323	    public IsRegistered(key: string): boolean {
324	        return this.m_templates.has(key);
325	    }
326	
327	    /**
328	     * @ch 取得所有已註冊的模板鍵值
329	     * @returns 鍵值陣列
330	     */
331	    public GetRegisteredKeys(): string[] {
332	        return Array.from(this.m_templates.keys());
333	    }
334	
335	    /**
336	     * @ch 設定除錯模式
337	     * @param enabled 是否啟用除錯
338	     */
339	    public SetDebugMode(enabled: boolean): void {
340	        this.m_debugMode = enabled;
341	    }
342	
343	    /**
344	     * @ch 印出所有物件池的狀態資訊
345	     */
346	    public LogPoolStatus(): void {
347	        console.log("=== PrefabPoolManager Status ===");
348	        console.log(`Total registered templates: ${this.m_templates.size}`);
349	        
350	        this.m_pools.forEach((pool, key) => {
351	            const size = pool.size();
352	            console.log(`Pool '${key}': ${size} nodes available`);
353	        });
354	        
355	        console.log("=== End of Status ===");
356	    }
357	
358	    /**
359	     * @ch 銷毀管理器（通常在場景切換時使用）
360	     */
361	    public Destroy(): void {
362	        this.ClearAllPools();
363	        this.m_pools.clear();
364	        this.m_templates.clear();
365	        PrefabPoolManager.instance = null;
366	        
367	        if (this.m_debugMode) {
368	            console.log("PrefabPoolManager: Destroyed");
369	        }
370	    }
371	}
372	
373	// 匯出單例實例供外部使用
374	export const prefabPoolManager = PrefabPoolManager.GetInstance();
375	
376	/*
377	使用範例：
378	
379	// 1. 註冊 Prefab（傳統方式）
380	prefabPoolManager.RegisterPrefab("bombEffect", bombPrefab, 5);
381	
382	// 2. 註冊 Node（新功能）
383	const effectNode = this.node.getChildByName("TemplateEffect");
384	prefabPoolManager.RegisterNode("customEffect", effectNode, 3);
385	
386	// 3. 使用通用的 RegisterTemplate
387	prefabPoolManager.RegisterTemplate("flexibleEffect", prefabOrNode, 2);
388	
389	// 4. 取得和使用節點（方法相同）
390	const bomb = prefabPoolManager.GetNode("bombEffect", this.effectContainer);
391	const custom = prefabPoolManager.GetNode("customEffect", this.node);
392	
393	// 5. 歸還節點（方法相同）
394	prefabPoolManager.ReturnNode("bombEffect", bomb);
395	prefabPoolManager.ReturnNode("customEffect", custom);
396	*/

