import { Node, Prefab, instantiate, NodePool, Vec3, sp, log } from 'cc';

/**
 * @ch 通用節點物件池管理器
 * 
 * 功能特色：
 * - 基於字符串鍵值的物件池管理
 * - 支援 Prefab 和 Node 作為模板
 * - 自動節點生命週期管理
 * - 提供便捷的節點取得和歸還方法
 * - 集中的記憶體管理和除錯功能
 * 
 * 使用場景：
 * - 炸彈效果系統
 * - 動態特效管理
 * - 可重用的 UI 元件
 * - 任何需要頻繁創建/銷毀節點的場景
 */
export class PrefabPoolManager {
    private static instance: PrefabPoolManager = null;

    /**@ch 物件池映射表 */
    private m_pools: Map<string, NodePool> = new Map();

    /**@ch 模板映射表（可以是 Prefab 或 Node） */
    private m_templates: Map<string, Prefab | Node> = new Map();

    /**@ch 預設池大小 */
    private readonly DEFAULT_POOL_SIZE: number = 1;

    /**@ch 是否啟用除錯日誌 */
    private m_debugMode: boolean = false;

    /** @ch GC 優化：快取節點的 Spine 元件列表，避免每次 get/return 遍歷子樹 */
    private m_spineCache: WeakMap<Node, sp.Skeleton[]> = new WeakMap();

    private constructor() {
        this.m_debugMode = false; // 可以通過外部設定開啟
    }

    /**@ch 取得單例實例 */
    public static GetInstance(): PrefabPoolManager {
        if (!PrefabPoolManager.instance) {
            PrefabPoolManager.instance = new PrefabPoolManager();
        }
        return PrefabPoolManager.instance;
    }

    /**
     * @ch GC 優化：取得快取的 Spine 元件列表（首次查詢後快取）
     * @param node 目標節點
     * @returns Spine 元件陣列
     */
    private getCachedSpines(node: Node): sp.Skeleton[] {
        let spines = this.m_spineCache.get(node);
        if (!spines) {
            spines = node.getComponentsInChildren(sp.Skeleton);
            this.m_spineCache.set(node, spines);
        }
        return spines;
    }

    /**
     * @ch 註冊模板（支援 Prefab 或 Node）
     * @param key 唯一識別鍵
     * @param template Prefab 資源或 Node 實例
     * @param preCreateCount 預先建立的節點數量（預設 1）
     */
    public RegisterTemplate(key: string, template: Prefab | Node, preCreateCount: number = this.DEFAULT_POOL_SIZE): void {
        if (!key || !template) {
            console.error('PrefabPoolManager: Invalid key or template');
            return;
        }

        if (this.m_templates.has(key)) {
            console.warn(`PrefabPoolManager: Key '${key}' already exists, overriding...`);
        }

        // 儲存模板
        this.m_templates.set(key, template);

        // 建立新的物件池
        const pool = new NodePool();
        pool.poolHandlerComp = null;

        // 預先建立節點到池中
        for (let i = 0; i < preCreateCount; i++) {
            const node = this.CreateNodeFromTemplate(template);
            if (node) {
                node.active = false;
                pool.put(node);
            }
        }

        this.m_pools.set(key, pool);

        if (this.m_debugMode) {
            const templateType = template instanceof Prefab ? 'Prefab' : 'Node';
            log(`PrefabPoolManager: Registered '${key}' (${templateType}) with ${preCreateCount} pre-created nodes`);
        }
    }

    /**
     * @ch 註冊 Prefab 類型（向後兼容）
     * @param key 唯一識別鍵
     * @param prefab Prefab 資源
     * @param preCreateCount 預先建立的節點數量（預設 1）
     */
    public RegisterPrefab(key: string, prefab: Prefab, preCreateCount: number = this.DEFAULT_POOL_SIZE): void {
        this.RegisterTemplate(key, prefab, preCreateCount);
    }

    /**
     * @ch 註冊 Node 類型
     * @param key 唯一識別鍵
     * @param node Node 實例（將作為模板使用）
     * @param preCreateCount 預先建立的節點數量（預設 1）
     */
    public RegisterNode(key: string, node: Node, preCreateCount: number = this.DEFAULT_POOL_SIZE): void {
        this.RegisterTemplate(key, node, preCreateCount);
    }

    /**
     * @ch 從模板創建節點
     * @param template Prefab 或 Node 模板
     * @returns 新的節點實例
     */
    private CreateNodeFromTemplate(template: Prefab | Node): Node {
        if (template instanceof Prefab) {
            return instantiate(template);
        } else {
            // 如果是 Node，創建一個副本
            const clonedNode = instantiate(template);
            return clonedNode;
        }
    }

    /**
     * @ch 取得節點
     * @param key 模板識別鍵
     * @param parent 父節點（可選）
     * @param position 位置（可選）
     * @param scale 縮放（可選）
     * @returns 節點實例
     */
    public GetNode(key: string, parent?: Node, position: Vec3 = Vec3.ZERO, scale: Vec3 = Vec3.ONE): Node {
        const pool = this.m_pools.get(key);
        const template = this.m_templates.get(key);

        if (!pool || !template) {
            console.error(`PrefabPoolManager: Key '${key}' not registered. Call RegisterTemplate/RegisterPrefab/RegisterNode first.`);
            return null;
        }

        let node: Node;

        // 嘗試從池中取得節點
        if (pool.size() > 0) {
            node = pool.get();
            if (this.m_debugMode) {
                log(`PrefabPoolManager: Retrieved '${key}' from pool (pool size: ${pool.size()})`);
            }
        } else {
            // 池中沒有節點，建立新的
            node = this.CreateNodeFromTemplate(template);
            if (this.m_debugMode) {
                log(`PrefabPoolManager: Created new '${key}' node (pool empty)`);
            }
        }

        // 設定節點屬性
        node.active = true;

        if (parent) {
            node.setParent(parent);
        }

        if (position) {
            node.setPosition(position);
        }

        if (scale) {
            node.setScale(scale);
        }

        // ⭐ 重新啟用所有 Spine 組件（使用快取避免遍歷子樹）
        const spines = this.getCachedSpines(node);
        if (spines && spines.length > 0) {
            spines.forEach(spine => {
                if (spine && !spine.enabled) {
                    spine.enabled = true;

                    if (this.m_debugMode) {
                        log(`PrefabPoolManager: Re-enabled Spine component on '${key}'`);
                    }
                }
            });
        }

        return node;
    }

    /**
     * @ch 歸還節點到物件池
     * @param key 模板識別鍵
     * @param node 要歸還的節點
     */
    public ReturnNode(key: string, node: Node): void {
        const pool = this.m_pools.get(key);

        if (!pool) {
            console.error(`PrefabPoolManager: Key '${key}' not found, cannot return node`);
            return;
        }

        if (!node || !node.isValid) {
            console.warn(`PrefabPoolManager: Invalid node for key '${key}'`);
            return;
        }

        // 重置節點狀態
        node.active = false;

        // ⭐ 新增：停用所有 Spine 組件（優化版：混合策略）
        // 優先處理根節點的 Spine 組件（大多數情況）
        const rootSpine = node.getComponent(sp.Skeleton);
        if (rootSpine && rootSpine.enabled) {
            rootSpine.clearTracks();       // 清除動畫軌道
            rootSpine.setToSetupPose();    // 重置為初始姿勢
            rootSpine.enabled = false;     // 停用組件

            if (this.m_debugMode) {
                log(`PrefabPoolManager: Disabled root Spine component on '${key}'`);
            }
        }

        // 只在有子節點時才處理子 Spine（使用快取避免遍歷子樹）
        if (node.children.length > 0) {
            const childSpines = this.getCachedSpines(node);

            childSpines.forEach(spine => {
                // 跳過已處理的根節點 Spine
                if (spine !== rootSpine && spine.enabled) {
                    spine.clearTracks();
                    spine.setToSetupPose();
                    spine.enabled = false;

                    if (this.m_debugMode) {
                        log(`PrefabPoolManager: Disabled child Spine component on '${key}'`);
                    }
                }
            });
        }

        node.removeFromParent();
        node.setScale(1, 1, 1);
        node.setPosition(0, 0, 0);

        // 歸還到池中
        pool.put(node);

        if (this.m_debugMode) {
            log(`PrefabPoolManager: Returned '${key}' to pool (pool size: ${pool.size()})`);
        }
    }

    /**
     * @ch 清理特定類型的物件池
     * @param key 模板識別鍵
     */
    public ClearPool(key: string): void {
        const pool = this.m_pools.get(key);

        if (!pool) {
            console.error(`PrefabPoolManager: Key '${key}' not found`);
            return;
        }

        const oldSize = pool.size();
        pool.clear();

        if (this.m_debugMode) {
            log(`PrefabPoolManager: Cleared pool '${key}' (${oldSize} nodes removed)`);
        }
    }

    /**
     * @ch 清理所有物件池
     */
    public ClearAllPools(): void {
        let totalCleared = 0;

        this.m_pools.forEach((pool, key) => {
            const size = pool.size();
            pool.clear();
            totalCleared += size;

            if (this.m_debugMode) {
                log(`PrefabPoolManager: Cleared pool '${key}' (${size} nodes)`);
            }
        });

        if (this.m_debugMode) {
            log(`PrefabPoolManager: Total ${totalCleared} nodes cleared from all pools`);
        }
    }

    /**
     * @ch 取得物件池大小
     * @param key 模板識別鍵
     * @returns 池中節點數量
     */
    public GetPoolSize(key: string): number {
        const pool = this.m_pools.get(key);
        return pool ? pool.size() : 0;
    }

    /**
     * @ch 檢查模板是否已註冊
     * @param key 模板識別鍵
     * @returns 是否已註冊
     */
    public IsRegistered(key: string): boolean {
        return this.m_templates.has(key);
    }

    /**
     * @ch 取得所有已註冊的模板鍵值
     * @returns 鍵值陣列
     */
    public GetRegisteredKeys(): string[] {
        return Array.from(this.m_templates.keys());
    }

    /**
     * @ch 設定除錯模式
     * @param enabled 是否啟用除錯
     */
    public SetDebugMode(enabled: boolean): void {
        this.m_debugMode = enabled;
    }

    /**
     * @ch 印出所有物件池的狀態資訊
     */
    public LogPoolStatus(): void {
        console.log("=== PrefabPoolManager Status ===");
        console.log(`Total registered templates: ${this.m_templates.size}`);

        this.m_pools.forEach((pool, key) => {
            const size = pool.size();
            console.log(`Pool '${key}': ${size} nodes available`);
        });

        console.log("=== End of Status ===");
    }

    /**
     * @ch 銷毀管理器（通常在場景切換時使用）
     */
    public Destroy(): void {
        this.ClearAllPools();
        this.m_pools.clear();
        this.m_templates.clear();
        PrefabPoolManager.instance = null;

        if (this.m_debugMode) {
            console.log("PrefabPoolManager: Destroyed");
        }
    }
}

// 匯出單例實例供外部使用
export const prefabPoolManager = PrefabPoolManager.GetInstance();

/*
使用範例：

// 1. 註冊 Prefab（傳統方式）
prefabPoolManager.RegisterPrefab("bombEffect", bombPrefab, 5);

// 2. 註冊 Node（新功能）
const effectNode = this.node.getChildByName("TemplateEffect");
prefabPoolManager.RegisterNode("customEffect", effectNode, 3);

// 3. 使用通用的 RegisterTemplate
prefabPoolManager.RegisterTemplate("flexibleEffect", prefabOrNode, 2);

// 4. 取得和使用節點（方法相同）
const bomb = prefabPoolManager.GetNode("bombEffect", this.effectContainer);
const custom = prefabPoolManager.GetNode("customEffect", this.node);

// 5. 歸還節點（方法相同）
prefabPoolManager.ReturnNode("bombEffect", bomb);
prefabPoolManager.ReturnNode("customEffect", custom);
*/

