import { Node, Prefab, instantiate, NodePool, log } from "cc";
import Game_Define from "../Game_Define";

/**
 * @ch 使用 cc.NodePool 的節點池管理器
 * 
 * 重構說明：
 * - 替換原本的手動三維陣列管理為 cc.NodePool
 * - 修正了 Singleton 模式的實作問題
 * - 增加了自動的記憶體管理和節點重用
 * - 提供了更好的錯誤處理和邊界檢查
 * - 新增了清理和查詢方法
 * 
 * 優勢：
 * - 使用 Cocos Creator 官方的 NodePool 實作
 * - 自動處理物件生命週期和記憶體清理
 * - 節點重用提升效能，減少 GC 壓力
 * - 更好的型別安全性和錯誤處理
 * - 符合 Cocos Creator 3.6.2 最佳實踐
 * 
 * 支援的效果類型：
 * - SYMBOL: 符號效果動畫
 * - ADD_EFFECT: 額外效果（如中獎框）
 * - FLY: 飛行特效
 */
export default class BaseNodePool
{
    private static _instance: BaseNodePool;

    private constructor() {}

    public static getInstance(): BaseNodePool
    {
        if (!BaseNodePool._instance)
        {
            BaseNodePool._instance = new BaseNodePool();
        }
        return BaseNodePool._instance;
    }

    /**@ch 各效果類型的預製體陣列 */
    private m_Prefabs: Array<Array<Prefab>> = [];

    /**@ch 各效果類型的 NodePool */
    private m_PoolMaps: Array<Array<NodePool>> = [];

    /**@ch 預製體預設池大小 */
    private m_PoolDefaultSize: number = 3;

    /**@ch 初始化物件池 */
    Init()
    {
        this.m_Prefabs.length = Game_Define.EFFECT_TYPES;
        this.m_PoolMaps.length = Game_Define.EFFECT_TYPES;

        for (let i = 0; i < Game_Define.EFFECT_TYPES; i++)
        {
            this.m_Prefabs[i] = [];
            this.m_PoolMaps[i] = [];
        }
    }

    /**@ch 設定預製體並建立對應的 NodePool */
    SetPrefabs(prefabs: Array<Prefab>, primaryType: number)
    {
        if (primaryType >= Game_Define.EFFECT_TYPES || primaryType < 0)
        {
            console.error(`Invalid primaryType: ${primaryType}`);
            return;
        }

        this.m_Prefabs[primaryType] = prefabs;
        this.m_PoolMaps[primaryType] = [];

        for (let i = 0; i < prefabs.length; i++)
        {
            const pool = new NodePool();
            pool.poolHandlerComp = null;

            // 預先建立一些節點到池中
            for (let j = 0; j < this.m_PoolDefaultSize; j++)
            {
                const node = instantiate(prefabs[i]);
                node.active = false;
                pool.put(node);
            }

            this.m_PoolMaps[primaryType][i] = pool;
        }
    }

    /**@ch 從物件池取得節點 */
    GetNode(primaryType: number, secondaryType: number): Node
    {
        if (primaryType >= Game_Define.EFFECT_TYPES || primaryType < 0)
        {
            throw new Error(`Invalid primaryType: ${primaryType}`);
        }

        if (!this.m_PoolMaps[primaryType] || !this.m_PoolMaps[primaryType][secondaryType])
        {
            throw new Error(`Pool not found for primaryType: ${primaryType}, secondaryType: ${secondaryType}. Make sure to call SetPrefabs first.`);
        }

        const pool = this.m_PoolMaps[primaryType][secondaryType];
        let node = pool.get();

        // 如果池中沒有節點，建立新的
        if (!node)
        {
            if (!this.m_Prefabs[primaryType] || !this.m_Prefabs[primaryType][secondaryType])
            {
                throw new Error(`Prefab not found for primaryType: ${primaryType}, secondaryType: ${secondaryType}`);
            }
            node = instantiate(this.m_Prefabs[primaryType][secondaryType]);
        }

        // 重置節點狀態
        node.active = true;
        return node;
    }

    /**@ch 歸還節點到物件池 */
    ReturnNode(primaryType: number, secondaryType: number, node: Node)
    {
        if (primaryType >= Game_Define.EFFECT_TYPES || primaryType < 0)
        {
            console.error(`Invalid primaryType: ${primaryType}`);
            return;
        }

        if (!this.m_PoolMaps[primaryType] || !this.m_PoolMaps[primaryType][secondaryType])
        {
            console.error(`Pool not found for primaryType: ${primaryType}, secondaryType: ${secondaryType}`);
            return;
        }

        // 重置節點狀態
        node.active = false;
        node.removeFromParent();
        node.setScale(1, 1, 1);
        node.setPosition(0, 0, 0);

        this.m_PoolMaps[primaryType][secondaryType].put(node);
    }

    /**@ch 清空特定類型的物件池 */
    ClearPool(primaryType: number, secondaryType?: number)
    {
        if (primaryType >= Game_Define.EFFECT_TYPES || primaryType < 0)
        {
            console.error(`Invalid primaryType: ${primaryType}`);
            return;
        }

        if (secondaryType !== undefined)
        {
            if (this.m_PoolMaps[primaryType] && this.m_PoolMaps[primaryType][secondaryType])
            {
                this.m_PoolMaps[primaryType][secondaryType].clear();
            }
        }
        else
        {
            if (this.m_PoolMaps[primaryType])
            {
                this.m_PoolMaps[primaryType].forEach(pool => {
                    if (pool) {
                        pool.clear();
                    }
                });
            }
        }
    }

    /**@ch 清空所有物件池 */
    ClearAllPools()
    {
        for (let i = 0; i < this.m_PoolMaps.length; i++)
        {
            if (this.m_PoolMaps[i])
            {
                this.m_PoolMaps[i].forEach(pool => {
                    if (pool) {
                        pool.clear();
                    }
                });
            }
        }
    }

    /**@ch 獲取物件池當前大小 */
    GetPoolSize(primaryType: number, secondaryType: number): number
    {
        if (primaryType >= Game_Define.EFFECT_TYPES || primaryType < 0)
        {
            return 0;
        }

        if (!this.m_PoolMaps[primaryType] || !this.m_PoolMaps[primaryType][secondaryType])
        {
            return 0;
        }

        return this.m_PoolMaps[primaryType][secondaryType].size();
    }

    /**@ch 印出所有物件池的大小資訊 */
    PoolSizeLog()
    {
        log("=== BaseNodePool Size Log ===");

        for (let primaryType = 0; primaryType < this.m_PoolMaps.length; primaryType++)
        {
            if (!this.m_PoolMaps[primaryType])
            {
                log(`PrimaryType[${primaryType}]: Not initialized`);
                continue;
            }

            log(`PrimaryType[${primaryType}]:`);

            for (let secondaryType = 0; secondaryType < this.m_PoolMaps[primaryType].length; secondaryType++)
            {
                const pool = this.m_PoolMaps[primaryType][secondaryType];
                if (pool)
                {
                    const size = pool.size();
                    log(`  SecondaryType[${secondaryType}]: ${size} nodes`);
                }
                else
                {
                    log(`  SecondaryType[${secondaryType}]: Pool not found`);
                }
            }
        }

        log("=== End of Pool Size Log ===");
    }
}

