7	export namespace CommonEffect
8	{
9	    export class ExtendsMath
10	    {
11	        //--------------------------------------------------------------------------------------------
12	        private constructor()
13	        {
14	
15	        }
16	        //--------------------------------------------------------------------------------------------
17	        /** 取得帕斯卡三角形的第 `line` 層 */
18	        public static PascalTriangleLine( line: number ): number[]
19	        {
20	            let ptArr: number[] = [ 1 ];
21	            for ( let i = 1; i < line; i++ )
22	            {
23	                ptArr[ i ] = ptArr[ i - 1 ] * ( line - i ) / i;
24	            }
25	            return ptArr;
26	        }
27	
28	        //--------------------------------------------------------------------------------------------
29	        /** 在指定範圍裡取隨機值 */
30	        public static RangedRandom( min: number, max: number ): number
31	        {
32	            return ( max - min ) * Math.random() + min;
33	        }
34	
35	        //--------------------------------------------------------------------------------------------
36	        /** 取得矩形範圍內隨機位置
37	         * @param origin 中心點位置
38	         * @param range  長寬大小 (px)
39	         * @param angle  旋轉角度 (DEG)
40	         */
41	        public static GetRandomRectPos( origin: Vec2, range: Vec2, angle: number ): Vec2
42	        {
43	            let vector = v2( ( this.RangedRandom( -range.x, range.x ) / 2 ) | 0,
44	                ( this.RangedRandom( -range.x, range.x ) / 2 ) | 0 ).rotate( angle * macro.RAD );
45	            return origin.add( vector );
46	        }
47	
48	        //--------------------------------------------------------------------------------------------
49	        /** 取得橢圓範圍內隨機位置
50	         * @param origin 中心點位置
51	         * @param range  長短軸大小 (px)
52	         * @param angle  橢圓旋轉角 (DEG)
53	         */
54	        public static GetRandomOvalPos( origin: Vec2, range: Vec2, angle: number ): Vec2
55	        {
56	            let ratio = range.y / Math.max( 1, range.x );
57	            let radius = Math.random() * range.x * 0.5;
58	            let radian = Math.random() * Math.PI * 2;
59	            let vector = v2( radius * Math.cos( radian ),
60	                radius * Math.sin( radian ) * ratio ).rotate( angle * macro.RAD );
61	            return origin.add( vector );
62	        }
63	
64	        //--------------------------------------------------------------------------------------------
65	        /** 同時縮放與翻轉
66	         * @param scaleMin  最小縮放比例
67	         * @param scaleMax  最大縮放比例
68	         * @param flipTimes 翻轉總次數
69	         * @param time      時間尺度 [0, 1]
