    private CleanSymbolAnim(col: number, row: number, layer: number) {
        const symbolSpine = this.m_symbolSpines[col][row][layer];
        if (symbolSpine) {
            BaseNodePool.getInstance().ReturnNode(
                Game_Define.EFFECT_TYPE.SYMBOL,
                symbolSpine.GetSymbolId(),
                symbolSpine.node
            );
            this.m_symbolSpines[col][row][layer] = null;
        }

        const addEffectNode = this.m_symbolAddEffectSpineNodes[col][row];
        if (addEffectNode) {
            BaseNodePool.getInstance().ReturnNode(
                Game_Define.EFFECT_TYPE.ADD_EFFECT,
                Game_Define.ADD_EFFECT_TYPE.WIN_FRAME_NORMAL,
                addEffectNode
            );
            this.m_symbolAddEffectSpineNodes[col][row] = null;
        }
    }

