        let multiplyFly = multiplyFlyNode.getComponent(MultiplyFlyUI);
        if (!multiplyFly) {
            error("multiplyFly");
            return;
        }
        multiplyFlyNode.setParent(this.m_effectNodes[Game_Define.LAYERS.MULTI_FLY]);
        multiplyFlyNode.setWorldPosition(targetPos);
        multiplyFlyNode.active = true;

        multiplyFly.SetWinValue(winValue);
        await multiplyFly.ShowWinValue(isLeft);
        PrefabPoolManager.GetInstance().ReturnNode(MULTI_FLY_PREFAB_KEY, multiplyFlyNode);
    }

    /**@ch 顯示 ODD 靜止不回收，返回 node 供後續更新*/
    async ShowStaticOdds(pos: number, text: string, isLeft: boolean): Promise<Node> {
