    /**@ch 更新已顯示的 node 文字後展開飛消失，然後回收*/
    async UpdateStaticAndFlyUp(node: Node, text: string, isLeft: boolean = true, resultText?: string, resultValue?: number, bet?: number) {
        if (!node) return;
        let multiplyFly = node.getComponent(MultiplyFlyUI);
        if (!multiplyFly) return;
        await multiplyFly.UpdateAndFlyUp(text, isLeft, resultText, resultValue, bet);
        // 飛行動畫非阻塞，延遲回收（飛行0.5s + 縮小0.15s + 放大0.15s + 停留0.5s + 淡出1.0s + buffer）
        this.scheduleOnce(() => {
            PrefabPoolManager.GetInstance().ReturnNode(MULTI_FLY_PREFAB_KEY, node);
        }, 2.5);
    }

    /**@ch 乘倍演出期間保留的贏分特效節點*/
    private m_pendingWinEffectNodes: { node: Node, col: number, row: number }[] = [];

    /**@ch 清除保留的贏分特效節點（乘倍演出結束後呼叫）*/
    public CleanPendingWinEffectNodes() {
        for (const item of this.m_pendingWinEffectNodes) {
            item.node.active = false;
            this.SetSymbolShow(item.col, item.row, true);
        }
        this.m_pendingWinEffectNodes = [];
    }

    /**@ch 暫存待顯示結果（等 EXPLODE 後）*/
    private m_pendingResults: { worldPos: Vec3, text: string, isLeft: boolean }[] = [];

    /**
     * @ch 顯示文字 → 往上飛消失（通用）
     */
    async ShowFlyUpEffect(pos: number, text: string, isLeft: boolean) {
        let targetPos = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos).getWorldPosition();
        await this.ShowFlyUpAtWorldPos(targetPos, text, isLeft);
    }

    /**@ch 在指定 world position 顯示文字 → 往上飛消失*/
    private async ShowFlyUpAtWorldPos(worldPos: Vec3, text: string, isLeft: boolean) {
        let multiplyFlyNode = PrefabPoolManager.GetInstance().GetNode(MULTI_FLY_PREFAB_KEY);
        if (!multiplyFlyNode) { error("multiplyFlyNode"); return; }
        let multiplyFly = multiplyFlyNode.getComponent(MultiplyFlyUI);
        if (!multiplyFly) { error("multiplyFly"); return; }
        multiplyFlyNode.setParent(this.m_effectNodes[Game_Define.LAYERS.MULTI_FLY]);
        multiplyFlyNode.setWorldPosition(worldPos);
        multiplyFlyNode.active = true;

        await multiplyFly.ShowAndFlyUp(text, isLeft);
        PrefabPoolManager.GetInstance().ReturnNode(MULTI_FLY_PREFAB_KEY, multiplyFlyNode);
    }

    /**@ch 添加 pending 結果（預存 world position）*/
    public AddPendingResult(pos: number, text: string, isLeft: boolean) {
        let worldPos = this.m_gameView.SlotReels.GetMiddleSymbolEmptyNodeFromPosition(pos).getWorldPosition();
        this.m_pendingResults.push({ worldPos, text, isLeft });
    }

    /**@ch EXPLODE 時同時顯示所有 pending 結果（並行 spawn）*/
    async ShowPendingMultiplyResults() {
        let promises: Promise<void>[] = [];
        for (const item of this.m_pendingResults) {
            promises.push(this.ShowFlyUpAtWorldPos(item.worldPos, item.text, item.isLeft));
        }
        this.m_pendingResults = [];
        await Promise.all(promises);
    }

    //#region WantedPoster

    /**
     * @ch 懸賞令消除表演（僅負責 Symbol Remove 動畫；乘倍底板更新由 WantedPosterState 編排層處理）
     * @param symbol 發動的懸賞令 Symbol ID
     * @param positions 該 Symbol 在盤面上的位置陣列（一維索引）
     */
    async WantedPosterExplodeEffect(
        symbol: number,
        positions: number[]
    ): Promise<void>
    {
        if ( positions.length === 0 )
        {
            return;
        }

        const promises = this._reusablePromises;
        promises.length = 0;
        let speed = this.m_gameView.IsHardStop ? 2 : 1;

        for ( let pos of positions )
        {
            let col = Math.floor( pos / Game_Define.ROW );
            let row = pos % Game_Define.ROW;

            // 清除該位置之前的動畫
            this.CleanSymbolAnimByPostion( pos, Game_Define.LAYERS.SYMBOL );

            // 建立 Symbol 消除動畫
            let symbolNode = this.CreateEffectNode_NodePool( col, row, Game_Define.LAYERS.SYMBOL, symbol );
            let symbolSpine = symbolNode.getComponent( SymbolSpine );

            // 建立消除特效
            let removeEffectNode = PrefabPoolManager.GetInstance().GetNode( SYMBOL_REMOVE_EFFECT_PREFAB_KEY );
            if ( !removeEffectNode )
            {
                error( "[WantedPosterExplodeEffect] removeEffectNode 取得失敗" );
                continue;
            }

            let removeEffect = removeEffectNode.getComponent( EffectSpine );
            if ( !removeEffect )
            {
                error( "[WantedPosterExplodeEffect] removeEffect 組件取得失敗" );
                PrefabPoolManager.GetInstance().ReturnNode( SYMBOL_REMOVE_EFFECT_PREFAB_KEY, removeEffectNode );
                continue;
            }

            removeEffectNode.setParent( this.m_effectNodes[ Game_Define.LAYERS.PRIATE ] );
            removeEffectNode.setWorldPosition( this.GetSymbolNodeWorldPos( col, row ) );

            this.SetSymbolShow(col, row, false);

            promises.push( new Promise(
                async ( resolve ) =>
                {
                    symbolSpine.SetTimeScale( speed );
                    symbolSpine.SetAnimKey( "Remove" );
                    symbolSpine.PlayAnim().then( () =>
                    {
                        symbolSpine.SetTimeScale( 1 );
                        this.CleanSymbolAnim( col, row, Game_Define.LAYERS.SYMBOL );
                    } );

                    removeEffect.SetTimeScale( speed );
                    removeEffect.PlayAnim().then( () =>
                    {
                        removeEffect.SetTimeScale( 1 );
                        PrefabPoolManager.GetInstance().ReturnNode( SYMBOL_REMOVE_EFFECT_PREFAB_KEY, removeEffectNode );
                        resolve();
                    } );
                }
            ) );
        }

        await Promise.all( promises );
    }

    /**
     * @ch 在指定世界座標 spawn 場上 Wanted Spine 並播 Symbol_In（同時起播全部）
     * @param worldPositions 每個位置的世界座標
     * @param baseSymbol 對應的 BaseSymbol（M1~M9）skin
     * @param multiplier 合併組的連乘倍率（純表演顯示，不參與結算）
     * @returns Promise<Node[]> 全部 Symbol_In 播完後 resolve，回傳實際 spawn 的節點陣列
     *
     * BC-1：Pool 取節點 + 切 skin + 設倍率 + 掛 TARGET 層 + 同時起播
     * BC-3：EH-3/EH-4 觸發時 spawnedNodes 為 worldPositions 真子集（已知降級）
     * EH-1：worldPositions 空陣列 → 立即回 []
     * EH-2：prefab 未設置 → method 開頭守衛，警告並回 []
     * EH-2（multiplier）：非有限數或 < 1 → 退回 1（純表演，不阻斷 spawn）
     * EH-3：GetNode 回 null → 跳過該位置
     * EH-4：節點上無 WantedPosterItem → 回收並跳過
     */
    async SpawnAndPlayWantedSymbolIn(
        worldPositions: Vec3[],
        baseSymbol: number,
        multiplier: number
    ): Promise<Node[]>
    {
        // EH-2：prefab 未設置（提前到 method 開頭，避免 EH-3 重複報 error）
        if ( !this.m_wantedSymbolSpinePrefab )
        {
            warn( '[EffectPlate] SpawnAndPlayWantedSymbolIn: m_wantedSymbolSpinePrefab 未設置，跳過' );
            return [];
        }

        // EH-1：空陣列
        if ( !worldPositions || worldPositions.length === 0 )
        {
            return [];
        }

        // EH-2（multiplier）：非有限數或 < 1 → 退回 1（純表演倍率，不阻斷 spawn）
        const safeMultiplier = ( Number.isFinite( multiplier ) && multiplier >= 1 ) ? multiplier : 1;

        const spawnedNodes: Node[] = [];
        const playPromises: Promise<void>[] = [];

        for ( const worldPos of worldPositions )
        {
            // EH-3
            const node = PrefabPoolManager.GetInstance().GetNode( WANTED_SYMBOL_SPINE_PREFAB_KEY );
            if ( !node )
            {
                error( '[EffectPlate] SpawnAndPlayWantedSymbolIn: GetNode 回 null，跳過位置', worldPos );
                continue;
            }

            node.setParent( this.m_effectNodes[ Game_Define.LAYERS.SCATTER ] );
            node.setWorldPosition( worldPos );
            node.setScale( this.m_wantedSymbolSpineScale, this.m_wantedSymbolSpineScale, this.m_wantedSymbolSpineScale );
            node.active = true;

            const item = node.getComponent( WantedPosterItem );
            if ( !item )
            {
                // EH-4
                error( '[EffectPlate] SpawnAndPlayWantedSymbolIn: prefab 上無 WantedPosterItem 元件，回收節點' );
                PrefabPoolManager.GetInstance().ReturnNode( WANTED_SYMBOL_SPINE_PREFAB_KEY, node );
                continue;
            }

            // 透過 WantedPosterItem API 切 skin + 設連乘倍率（純表演）
            item.SetSkin( baseSymbol );
            item.SetFieldMultiplier( safeMultiplier );

            spawnedNodes.push( node );
            // Symbol_In 播完 stay at last frame（PlaySymbolIn 內部 loop=false）
            AudioManager.Play(AudioManager.AudioClips.Wanted_in);
            playPromises.push( item.PlaySymbolIn() );
        }

        await Promise.all( playPromises );
        return spawnedNodes;
    }

    /**
     * @ch 對 spawn 的節點群同時播 Symbol_Active，播完歸還 pool
     * @param nodes SpawnAndPlayWantedSymbolIn 回傳的節點陣列
     *
     * BC-2：同時起播 PlaySymbolActive；播完 active=false + 歸還 pool
     * EH-5：nodes 空陣列 → 立即 resolve
     * EH-6：節點上無 WantedPosterItem → 直接回收，跳過
     */
    async PlayWantedSymbolActiveAndRecycle( nodes: Node[] ): Promise<void>
    {
        // EH-5
        if ( !nodes || nodes.length === 0 )
        {
            return;
        }

        const playPromises: Promise<void>[] = [];
        for ( const node of nodes )
        {
            const item = node.getComponent( WantedPosterItem );
            if ( !item )
            {
                // EH-6
                warn( '[EffectPlate] PlayWantedSymbolActiveAndRecycle: 節點上無 WantedPosterItem，直接回收' );
                PrefabPoolManager.GetInstance().ReturnNode( WANTED_SYMBOL_SPINE_PREFAB_KEY, node );
                continue;
            }
            AudioManager.Play(AudioManager.AudioClips.Wanted_burn);
            playPromises.push(
                item.PlaySymbolActive().then( () => {
                    node.active = false;
                    PrefabPoolManager.GetInstance().ReturnNode( WANTED_SYMBOL_SPINE_PREFAB_KEY, node );
                } )
            );
        }
        await Promise.all( playPromises );
    }

    //#endregion WantedPoster

    //#region Eliminate

    /** Symbol 消除表演
     * @description 時間2s，Win 1s + Remove 1s
     * */
    async ExplodeEffect( awardDataVec: protocol.ar2pq9Proto.IAwardData[], comboIdx: number )
    {
        // 解除 NearWin 炸彈壓黑，避免迴圈多次
        if ( comboIdx == 0 )
        {
            eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW, false, false);

        }
        const promises = this._reusablePromises;
        promises.length = 0;
        // 配合音效做加速
        let speed = this.m_gameView.IsHardStop ? 2 : 1;
        for ( let awardData of awardDataVec )
        {
            let symbol = awardData.Symbol ? awardData.Symbol : 0;
            let posVec = awardData.EliminatePos;
            let isTargetSymbol = symbol === Game_Define.Symbol.Target || symbol === Game_Define.Symbol.GoldTarget;
            for ( let pos of posVec )
            {
                let col = Math.floor( pos / Game_Define.ROW );
                let row = pos % Game_Define.ROW;

                // 標靶消除範圍：用盤面實際 symbol 播 Remove，標靶自己位置跳過
                if (isTargetSymbol) {
                    // 標靶自己的位置不播（已由 PlayTargetExplodeEffect 處理）
                    const curPlateSymbol = this.m_gameView.SpinAck
                        .RoundQueue[this.m_gameView.CurRoundIndex]
                        .PlateQueue[this.m_gameView.CurPlateIndex]?.PlateSymbol;
                    const actualSymbol = (curPlateSymbol && curPlateSymbol[col]?.Col?.[row]) ?? symbol;
                    if (actualSymbol === Game_Define.Symbol.Target || actualSymbol === Game_Define.Symbol.GoldTarget) {
                        continue;
                    }
                    // 範圍內其他 symbol：用實際 symbol 播 Remove
                    symbol = actualSymbol;
                }

                let symbolNode = this.CreateEffectNode_NodePool(col, row, Game_Define.LAYERS.SYMBOL, symbol);

                let removeEffectNode = PrefabPoolManager.GetInstance().GetNode(SYMBOL_REMOVE_EFFECT_PREFAB_KEY);
                if (!removeEffectNode) {
                    error("removeEffectNode");
                    return;
                }


                // 取得 Spine 組件
                let removeEffect = removeEffectNode.getComponent(EffectSpine);
                if (!removeEffect) {
                    error("removeEffect");
                    PrefabPoolManager.GetInstance().ReturnNode(
                        SYMBOL_REMOVE_EFFECT_PREFAB_KEY,
                        removeEffectNode
                    );
                    return;
                }

                // 設定父節點
                removeEffectNode.setParent(this.m_effectNodes[Game_Define.LAYERS.PRIATE]);
                removeEffectNode.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));

                let symbolSpine = symbolNode.getComponent( SymbolSpine );
                promises.push( new Promise(
                    async ( resolve ) =>
                    {
                        symbolSpine.SetTimeScale( speed );
                        symbolSpine.SetAnimKey("Remove");
                        symbolSpine.PlayAnim().then( () =>
                        {
                            symbolSpine.SetTimeScale( 1 );
                            this.CleanSymbolAnim(col, row, Game_Define.LAYERS.SYMBOL);
                        } );

                        removeEffect.SetTimeScale( speed );
                        removeEffect.PlayAnim().then( () =>
                        {
                            removeEffect.SetTimeScale( 1 );
                            PrefabPoolManager.GetInstance().ReturnNode(SYMBOL_REMOVE_EFFECT_PREFAB_KEY, removeEffectNode);
                            resolve();
                        } );


                    }
                ) );
            }
        }
        // 消除音效（已移除，改由乘倍階段播）
        let comboLvl = comboIdx >= 5 ? 5 : comboIdx + 1;
        let suffix = this.m_gameView.IsHardStop ? "_F" : "";
        let soundKey = `Combo_0${comboLvl}${suffix}`;
        // AudioManager.Play(AudioManager.AudioClips[soundKey]);
        eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW, true, false);
        await Promise.all( promises );

        eventManager.Dispatch(REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW, false, false);
    }

    /** 消除調整節點 Row
     * @description 傳入的位置應沒有動態節點，不必回收節點
    */
    TileMatching( col: number, row: number)
    {

        this.m_symbolSpines[ col ].splice( row, 1 );

        let newLayerSpines = new Array<SymbolSpine>();
        newLayerSpines.length = Game_Define.EFFECT_LAYER_NUMS;
        this.m_symbolSpines[ col ].push(newLayerSpines);
    }

