import { _decorator, Component, Node ,log} from 'cc';
import { BaseSpine } from '../Spine/BaseSpine';
import { Symbol } from '../Game_Define';
import { Define } from 'db://astarte-framework/utilis';
const { ccclass, property } = _decorator;

@ccclass('EffectSpine')
export class EffectSpine extends Component {
    @property( {
        type: Node,
        displayName: "Spine Root Node"
    } )
    protected m_spineRootNode: Node = null;

    @property( {
        type: BaseSpine,
        displayName: "Spine"
    } )
    protected m_spine: BaseSpine = null;

    @property( {
        type: String,
        displayName: "Spine Skin",
    } )
    protected m_skinName: string = "default";

    @property( {
        type: String,
        displayName: "Spine 動畫鍵"
    } )
    protected m_spineAnimKey: string = "";

    @property( {
        type: Boolean,
        displayName: "播完動畫後是否需要換成靜態圖片"
    } )
    protected m_isNeedSwitchStaticImage: boolean = false;

    @property( {
        type: Node,
        displayName: "靜態圖片",
        visible: function(this: EffectSpine) {
            return this.m_isNeedSwitchStaticImage;
        }
    } )
    protected m_staticImageNode: Node = null;

    @property( {
        type: Number,
        displayName: "Spine 播放delay時間"
    } )
    protected m_spinePlayDelayTime: number = -1;

    @property( {
        type: Number,
        displayName: "播放速度"
    } )
    protected m_timeScale: number = 1;


    /**
     * @ch 設定播放速度
     * @param timeScale 播放速度
     */
    public SetTimeScale(timeScale: number) {
        this.m_timeScale = timeScale;
    }

    /**
     * @ch 設定spine Anim Key
     * @param animKey 動畫鍵
     */
    public SetAnimKey(animKey: string) {
        this.m_spineAnimKey = animKey;
    }

    /**
     * @ch 設定spine Skin
     * @param skin 皮膚名稱
     */
    public SetSkin(skin: string) {
        this.m_skinName = skin;
    }

    /**
     * @ch 播放動畫
     * @param isCloseSpine 是否播完後關閉Bingo Spine
     * @param isLoop 是否循環播放
     */
    public async PlayAnim(isCloseSpine: boolean = false, isLoop: boolean = false) : Promise<void> {
        this.SetSpineRootNodeShow(true);
        this.SetStaticImageShow(false);

        // 播放動畫
        let promises: Promise<boolean>[] = [];

        const spine = this.m_spine;
        spine.SetSkin(this.m_skinName);
        spine.SetNodeActivity(true);
        const promise = spine.PlayAnimation(this.m_spineAnimKey, spine.Spine, isLoop, this.m_timeScale);
        if (!isLoop) {
            promises.push(promise);
        }

        if (this.m_spinePlayDelayTime > 0) {
            await Define.Wait(this, this.m_spinePlayDelayTime * this.m_timeScale);
        }

        if (promises.length > 0) {
            await Promise.all(promises);
        }

        // 關閉 Spine
        if (isCloseSpine) {
            this.SetSpinesShow(false);
            this.SetSpineRootNodeShow(false);
        }

        // 若需要換成靜態圖片，則設置靜態圖片Activity
        if (this.m_isNeedSwitchStaticImage) {
            this.SetStaticImageShow(true);
        }

        return Promise.resolve();
    }



    /**
     * @ch 設置Spine的顯示狀態
     * @param isShow 是否顯示
     */
    private SetSpinesShow(isShow: boolean) {
        if (!this.m_spine) return;
        this.m_spine.SetNodeActivity(isShow);
    }

    /**
     * @ch 設置靜態圖片顯示狀態
     * @param isShow 是否顯示
     */
    public SetStaticImageShow(isShow: boolean) {
        if (this.m_staticImageNode) {
            this.m_staticImageNode.active = isShow;
        }
    }

    /**
     * @ch 設置Bingo Root Node 顯示狀態
     * @param isShow 是否顯示
     */
    private SetSpineRootNodeShow(isShow: boolean) {
        if (this.m_spineRootNode) {
            this.m_spineRootNode.active = isShow;
        }
    }
}

