1	import { _decorator, Component, Label, Node, tween, Vec3, UITransform, UIOpacity, Camera, view, director } from 'cc';
2	const { ccclass, property } = _decorator;
3	import { Define } from 'db://astarte-framework/utilis';
4	
5	@ccclass('MultiplyFlyUI')
6	export class MultiplyFlyUI extends Component {
7	
8	    // ── GC 優化：tween 目標常量化，避免每次動畫 new Vec3 ──
9	    private static readonly SCALE_ONE = new Vec3(1, 1, 1);
10	    private static readonly SCALE_TWO = new Vec3(2, 2, 2);
11	    private static readonly SCALE_SHRINK = new Vec3(0.3, 0.3, 0.3);
12	
13	    // ── GC 優化：動態值用實例層級復用 Vec3，避免每次飛入 new ──
14	    private _flyDeltaVec3 = new Vec3();
15	    private _dynamicScaleVec3 = new Vec3();
16	
17	    @property({
18	        type: Label,
19	        tooltip: "贏分 Label（預設 / <10x bet）"
20	    })
21	    private m_winValueLabel: Label = null;
22	
23	    @property({
24	        type: Label,
25	        tooltip: "結果 Label（10x~25x bet）"
26	    })
27	    private m_winValueLabel_10x: Label = null;
28	
29	    @property({
30	        type: Label,
31	        tooltip: "結果 Label（≥25x bet）"
32	    })
33	    private m_winValueLabel_25x: Label = null;
34	
35	    @property({
36	        type: Node,
37	        tooltip: "Shadow 背景節點"
38	    })
39	    private m_shadow: Node = null;
40	
41	    /**@ch 根據 resultValue / bet 倍率選擇對應 Label，回傳該 Label（fallback 到 m_winValueLabel）*/
42	    private getResultLabel(resultValue: number, bet: number): Label {
43	        if (bet <= 0) return this.m_winValueLabel;
44	        const ratio = resultValue / bet;
45	        if (ratio >= 25 && this.m_winValueLabel_25x) {
46	            return this.m_winValueLabel_25x;
47	        } else if (ratio >= 10 && this.m_winValueLabel_10x) {
48	            return this.m_winValueLabel_10x;
49	        }
50	        return this.m_winValueLabel;
51	    }
52	
53	    /**@ch 暫存本次 UpdateAndFlyUp 切換到的結果 Label（null=使用原始 m_winValueLabel）*/
54	    private _activeResultLabel: Label = null;
55	
56	    /**@ch 根據倍率取得結果放大 scale */
57	    private getResultScale(resultValue: number, bet: number): number {
58	        if (bet <= 0) return 1.0;
59	        const ratio = resultValue / bet;
60	        if (ratio >= 25) return 1.3;
61	        if (ratio >= 10) return 1.15;
62	        return 1.0;
63	    }
64	
65	    /**@ch 同步 Shadow 寬度到 Label */
66	    private syncShadowSize(): void {
67	        if (!this.m_shadow) return;
68	        const activeLabel = this._activeResultLabel || this.m_winValueLabel;
69	        if (!activeLabel) return;
70	        activeLabel.updateRenderData(true);
71	        const labelUT = activeLabel.node.getComponent(UITransform);
72	        const labelWidth = labelUT.contentSize.width;
73	        const shadowUT = this.m_shadow.getComponent(UITransform);
74	        const padding = 20;
75	        shadowUT.setContentSize(labelWidth + padding, shadowUT.contentSize.height);
76	        shadowUT.anchorX = labelUT.anchorX;
77	        const labelPos = activeLabel.node.position;
78	        this.m_shadow.setPosition(labelPos.x, labelPos.y - 10, 0);
79	    }
80	
81	    /** @ch 快取的 Camera 引用，避免每次 getClampedX 遍歷場景樹 */
82	    private _cachedCam: Camera = null;
83	
84	    /** @ch 取得快取的 Camera（lazy init） */
85	    private getCachedCamera(): Camera | null {
86	        if (!this._cachedCam) {
87	            const cameras = director.getScene().getComponentsInChildren(Camera);
88	            this._cachedCam = cameras.find(c => c.node.name === 'Camera') || cameras[0];
89	        }
90	        return this._cachedCam;
91	    }
92	
93	    /** @ch 取得 clamp 後的 local x 偏移，確保文字不超出螢幕 */
94	    private getClampedX(anchorX: number = 0.5): number {
95	        // 強制 Label 重算 contentSize
96	        this.m_winValueLabel.updateRenderData(true);
97	        const uiTransform = this.m_winValueLabel.node.getComponent(UITransform);
98	        const textWidth = uiTransform.contentSize.width;
99	
100	        // 使用快取的 Camera 引用
101	        const cam = this.getCachedCamera();
102	        if (!cam) return 0;
103	
104	        const orthoH = cam.orthoHeight;
105	        const aspect = cam.camera.aspect || (view.getVisibleSize().width / view.getVisibleSize().height);
106	        const screenW = orthoH * aspect * 2;
107	        const margin = screenW * 0.075;
108	
109	        const camX = cam.node.worldPosition.x;
110	        const leftBound = camX - screenW / 2 + margin;
111	        const rightBound = camX + screenW / 2 - margin;
112	
113	        const worldX = this.node.worldPosition.x;
114	        const leftEdge = worldX - anchorX * textWidth;
115	        const rightEdge = worldX + (1 - anchorX) * textWidth;
116	
117	        let offsetX = 0;
118	        if (leftEdge < leftBound) {
119	            offsetX = leftBound - leftEdge;
120	        } else if (rightEdge > rightBound) {
121	            offsetX = rightBound - rightEdge;
122	        }
123	        return offsetX;
124	    }
125	
126	    /**@ch 顯示文字靜止不消失，從大縮到正常 + 淡入*/
127	    public async ShowStatic(text: string, isLeft: boolean) {
128	        this.m_winValueLabel.string = text;
129	        this.m_winValueLabel.node.active = true;
130	        this.m_winValueLabel.node.getComponent(UITransform).anchorX = 0.5;
131	
132	        const offsetX = this.getClampedX();
133	        const offsetY = 50;
134	        this.m_winValueLabel.node.setPosition(offsetX, offsetY, 0);
135	        this.syncShadowSize();
136	
137	        let opacity = this.m_winValueLabel.node.getComponent(UIOpacity);
138	        if (!opacity) { opacity = this.m_winValueLabel.node.addComponent(UIOpacity); }
139	        opacity.opacity = 0;
140	
141	        this.m_winValueLabel.node.setScale(2, 2, 2);
142	        await new Promise<void>((resolve) => {
143	            tween(this.m_winValueLabel.node)
144	                .to(0.2, { scale: MultiplyFlyUI.SCALE_ONE })
145	                .call(() => resolve())
146	                .start();
147	            tween(opacity)
148	                .to(0.2, { opacity: 255 })
149	                .start();
150	        });
151	    }
152	
153	    /**@ch 更新文字後往上飛離，移動中途切換為結果數字（根據 resultValue/bet 倍率選 label）*/
154	    public async UpdateAndFlyUp(text: string, isLeft: boolean = true, resultText?: string, resultValue?: number, bet?: number) {
155	        // 切 anchorX=0 前記錄原文字左邊緣位置，切完後補償使左邊不動
156	        this.m_winValueLabel.updateRenderData(true);
157	        const uiTransform = this.m_winValueLabel.node.getComponent(UITransform);
158	        const oldWidth = uiTransform.contentSize.width;
159	        const oldAnchorX = uiTransform.anchorX;
160	        const oldPos = this.m_winValueLabel.node.position;
161	        const oldLeftX = oldPos.x - oldAnchorX * oldWidth;
162	
163	        this.m_winValueLabel.string = text;
164	        uiTransform.anchorX = 0;
165	        this.m_winValueLabel.updateRenderData(true);
166	        const newWidth = uiTransform.contentSize.width;
167	
168	        // 左邊起點不變，只往右長；碰右邊界再推回
169	        let targetX = oldLeftX;
170	        const offsetX = this.getClampedX(0);
171	        if (offsetX < 0) targetX += offsetX;
172	
173	        const offsetY = oldPos.y;
174	        this.m_winValueLabel.node.setPosition(targetX, offsetY, 0);
175	        this.syncShadowSize();
176	
177	        let opacity = this.m_winValueLabel.node.getComponent(UIOpacity);
178	        if (!opacity) { opacity = this.m_winValueLabel.node.addComponent(UIOpacity); }
179	        opacity.opacity = 255;
180	
181	        const flyUpDistance = 15;
182	        const flyDuration = 0.5;
183	        const shrinkDuration = 0.15;
184	        const growDuration = 0.15;
185	
186	        // 重置 activeResultLabel
187	        this._activeResultLabel = null;
188	
189	        // 非阻塞：往上飛 → 算式縮小淡出 → 結果放大淡入 → 淡出消失
190	        this._flyDeltaVec3.set(0, flyUpDistance, 0);
191	        tween(this.m_winValueLabel.node)
192	            .by(flyDuration, { position: this._flyDeltaVec3 }, { easing: 'cubicOut' })
193	            .call(() => {
194	                // 飛到頂：切回置中再縮小（避免往左角收）
195	                uiTransform.anchorX = 0.5;
196	                this.m_winValueLabel.updateRenderData(true);
197	                const curW = uiTransform.contentSize.width;
198	                const curPos = this.m_winValueLabel.node.position;
199	                // anchorX 0→0.5 補償：原本左邊緣位置 + 半寬 = 新中心位置
200	                this.m_winValueLabel.node.setPosition(curPos.x + curW * 0.5, curPos.y, 0);
201	                this.syncShadowSize();
202	            })
203	            // 飛到頂：算式縮小淡出
204	            .to(shrinkDuration, { scale: MultiplyFlyUI.SCALE_SHRINK })
205	            .call(() => {
206	                // 切成結果數字：根據倍率選用對應 label
207	                if (resultText) {
208	                    const targetLabel = this.getResultLabel(resultValue || 0, bet || 0);
209	                    if (targetLabel !== this.m_winValueLabel) {
210	                        // 切換到另一個 label
211	                        this.m_winValueLabel.node.active = false;
212	                        targetLabel.node.active = true;
213	                        targetLabel.string = resultText;
214	                        targetLabel.node.getComponent(UITransform).anchorX = 0.5;
215	                        const curPos = this.m_winValueLabel.node.position;
216	                        targetLabel.node.setPosition(curPos.x, curPos.y, 0);
217	                        targetLabel.node.setScale(0.3, 0.3, 0.3);
218	                        this._activeResultLabel = targetLabel;
219	                    } else {
220	                        this.m_winValueLabel.string = resultText;
221	                        this.m_winValueLabel.node.getComponent(UITransform).anchorX = 0.5;
222	                        const curPos = this.m_winValueLabel.node.position;
223	                        const clampX = this.getClampedX(0.5);
224	                        this.m_winValueLabel.node.setPosition(clampX || curPos.x, curPos.y, 0);
225	                        this.m_winValueLabel.node.setScale(0.3, 0.3, 0.3);
226	                    }
227	                    this.syncShadowSize();
228	                }
229	
230	                // 結果放大淡入 → 停留 → 淡出（作用在正確的 node）
231	                const resultNode = this._activeResultLabel ? this._activeResultLabel.node : this.m_winValueLabel.node;
232	                let resultOpacity = resultNode.getComponent(UIOpacity);
233	                if (!resultOpacity) { resultOpacity = resultNode.addComponent(UIOpacity); }
234	                resultOpacity.opacity = 0;
235	
236	                const finalScale = this.getResultScale(resultValue || 0, bet || 0);
237	
238	                // Shadow 也要跟結果同步放大
239	                if (this.m_shadow) {
240	                    this.m_shadow.setScale(0.3, 0.3, 0.3);
241	                    let shadowOpacity = this.m_shadow.getComponent(UIOpacity);
242	                    if (!shadowOpacity) { shadowOpacity = this.m_shadow.addComponent(UIOpacity); }
243	                    shadowOpacity.opacity = 0;
244	
245	                    // Shadow 跟結果同步放大 + 淡入
246	                    this._dynamicScaleVec3.set(finalScale, finalScale, finalScale);
247	                    tween(this.m_shadow)
248	                        .to(growDuration, { scale: this._dynamicScaleVec3 })
249	                        .start();
250	                    tween(shadowOpacity)
251	                        .to(growDuration, { opacity: 255 })
252	                        .start();
253	                }
254	
255	                tween(resultNode)
256	                    .to(growDuration, { scale: this._dynamicScaleVec3 })
257	                    .delay(0.5)
258	                    .call(() => {
259	                        // 最終淡出：結果 + shadow 同步
260	                        const fadeDuration = 0.4;
261	                        tween(resultOpacity)
262	                            .to(fadeDuration, { opacity: 0 })
263	                            .call(() => {
264	                                this.resetAllLabels();
265	                            })
266	                            .start();
267	                        if (this.m_shadow) {
268	                            let shadowOp = this.m_shadow.getComponent(UIOpacity);
269	                            if (shadowOp) {
270	                                tween(shadowOp)
271	                                    .to(fadeDuration, { opacity: 0 })
272	                                    .start();
273	                            }
274	                        }
275	                    })
276	                    .start();
277	
278	                tween(resultOpacity)
279	                    .to(growDuration, { opacity: 255 })
280	                    .start();
281	            })
282	            .start();
283	
284	        // 算式 label 的透明度：飛行時保持 → 縮小同時淡出
285	        tween(opacity)
286	            .delay(flyDuration)
287	            .to(shrinkDuration, { opacity: 0 })
288	            .start();
289	    }
290	
291	    /**@ch 重置所有 label 到初始狀態（UpdateAndFlyUp 結束時呼叫）*/
292	    private resetAllLabels(): void {
293	        this.m_winValueLabel.node.setPosition(0, 0, 0);
294	        this.m_winValueLabel.node.setScale(1, 1, 1);
295	        this.m_winValueLabel.node.active = false;
296	        let op = this.m_winValueLabel.node.getComponent(UIOpacity);
297	        if (op) op.opacity = 255;
298	
299	        if (this.m_winValueLabel_10x) {
300	            this.m_winValueLabel_10x.node.setPosition(0, 0, 0);
301	            this.m_winValueLabel_10x.node.setScale(1, 1, 1);
302	            this.m_winValueLabel_10x.node.active = false;
303	            let op10 = this.m_winValueLabel_10x.node.getComponent(UIOpacity);
304	            if (op10) op10.opacity = 255;
305	        }
306	        if (this.m_winValueLabel_25x) {
307	            this.m_winValueLabel_25x.node.setPosition(0, 0, 0);
308	            this.m_winValueLabel_25x.node.setScale(1, 1, 1);
309	            this.m_winValueLabel_25x.node.active = false;
310	            let op25 = this.m_winValueLabel_25x.node.getComponent(UIOpacity);
311	            if (op25) op25.opacity = 255;
312	        }
313	        // 重置 shadow 透明度 + scale
314	        if (this.m_shadow) {
315	            this.m_shadow.setScale(1, 1, 1);
316	            let shadowOp = this.m_shadow.getComponent(UIOpacity);
317	            if (shadowOp) shadowOp.opacity = 255;
318	        }
319	        this._activeResultLabel = null;
320	    }
321	
322	    /**@ch 顯示文字 → 停留 → 原地淡出*/
323	    public async ShowAndFlyUp(text: string, isLeft: boolean) {
324	        this.m_winValueLabel.string = text;
325	        this.m_winValueLabel.node.active = true;
326	        this.m_winValueLabel.node.getComponent(UITransform).anchorX = 0.5;
327	
328	        const offsetX = this.getClampedX();
329	        const offsetY = 50;
330	        this.m_winValueLabel.node.setPosition(offsetX, offsetY, 0);
331	        this.syncShadowSize();
332	        this.m_winValueLabel.node.setScale(2, 2, 2);
333	
334	        let opacity = this.m_winValueLabel.node.getComponent(UIOpacity);
335	        if (!opacity) { opacity = this.m_winValueLabel.node.addComponent(UIOpacity); }
336	        opacity.opacity = 0;
337	
338	        await new Promise<void>((resolve) => {
339	            tween(this.m_winValueLabel.node)
340	                .delay(0.2)
341	                .to(0.1, { scale: MultiplyFlyUI.SCALE_ONE })
342	                .start();
343	            tween(opacity)
344	                .delay(0.2)
345	                .to(0.1, { opacity: 255 })
346	                .delay(0.25)
347	                .to(0.15, { opacity: 0 })
348	                .call(() => {
349	                    this.m_winValueLabel.node.setPosition(0, 0, 0);
350	                    this.m_winValueLabel.node.active = false;
351	                    // 重置 shadow 透明度
352	                    if (this.m_shadow) {
353	                        let shadowOp = this.m_shadow.getComponent(UIOpacity);
354	                        if (shadowOp) shadowOp.opacity = 255;
355	                    }
356	                    resolve();
357	                })
358	                .start();
359	            // Shadow 同步淡出
360	            if (this.m_shadow) {
361	                let shadowOpacity = this.m_shadow.getComponent(UIOpacity);
362	                if (!shadowOpacity) { shadowOpacity = this.m_shadow.addComponent(UIOpacity); }
363	                tween(shadowOpacity)
364	                    .delay(0.2 + 0.1 + 0.25)  // 跟 label 淡出同步
365	                    .to(0.15, { opacity: 0 })
366	                    .start();
367	            }
368	        });
369	    }
370	
371	    // 保留舊方法相容性（若有其他地方呼叫）
372	    public SetWinValue(winValue: string): void {
373	        this.m_winValueLabel.string = winValue.toString();
374	    }
375	
376	    public async ShowWinValue(isLeft: boolean) {
377	        await this.ShowAndFlyUp(this.m_winValueLabel.string, isLeft);
378	    }
379	}
