    private _dynamicScaleVec3 = new Vec3();

    @property({
        type: Label,
        tooltip: "贏分 Label（預設 / <10x bet）"
    })
    private m_winValueLabel: Label = null;

    @property({
        type: Label,
        tooltip: "結果 Label（10x~25x bet）"
    })
    private m_winValueLabel_10x: Label = null;

    @property({
        type: Label,
        tooltip: "結果 Label（≥25x bet）"
    })
    private m_winValueLabel_25x: Label = null;

    @property({
        type: Node,
        tooltip: "Shadow 背景節點"
    })
    private m_shadow: Node = null;

    /**@ch 根據 resultValue / bet 倍率選擇對應 Label，回傳該 Label（fallback 到 m_winValueLabel）*/
    private getResultLabel(resultValue: number, bet: number): Label {
        if (bet <= 0) return this.m_winValueLabel;
        const ratio = resultValue / bet;
        if (ratio >= 25 && this.m_winValueLabel_25x) {
            return this.m_winValueLabel_25x;
        } else if (ratio >= 10 && this.m_winValueLabel_10x) {
            return this.m_winValueLabel_10x;
        }
        return this.m_winValueLabel;
    }

    /**@ch 暫存本次 UpdateAndFlyUp 切換到的結果 Label（null=使用原始 m_winValueLabel）*/
    private _activeResultLabel: Label = null;

    /**@ch 根據倍率取得結果放大 scale */
    private getResultScale(resultValue: number, bet: number): number {
        if (bet <= 0) return 1.0;
        const ratio = resultValue / bet;
        if (ratio >= 25) return 1.3;
        if (ratio >= 10) return 1.15;
        return 1.0;
    }

    /**@ch 同步 Shadow 寬度到 Label */
    private syncShadowSize(): void {
        if (!this.m_shadow) return;
        const activeLabel = this._activeResultLabel || this.m_winValueLabel;
        if (!activeLabel) return;
        activeLabel.updateRenderData(true);
        const labelUT = activeLabel.node.getComponent(UITransform);
        const labelWidth = labelUT.contentSize.width;
        const shadowUT = this.m_shadow.getComponent(UITransform);
        const padding = 20;
        shadowUT.setContentSize(labelWidth + padding, shadowUT.contentSize.height);
        shadowUT.anchorX = labelUT.anchorX;
        const labelPos = activeLabel.node.position;
        this.m_shadow.setPosition(labelPos.x, labelPos.y - 10, 0);
    }

    /** @ch 快取的 Camera 引用，避免每次 getClampedX 遍歷場景樹 */
    private _cachedCam: Camera = null;

    /** @ch 取得快取的 Camera（lazy init） */
    private getCachedCamera(): Camera | null {
        if (!this._cachedCam) {
            const cameras = director.getScene().getComponentsInChildren(Camera);
            this._cachedCam = cameras.find(c => c.node.name === 'Camera') || cameras[0];
        }
        return this._cachedCam;
    }

    /** @ch 取得 clamp 後的 local x 偏移，確保文字不超出螢幕 */
    private getClampedX(anchorX: number = 0.5): number {
        // 強制 Label 重算 contentSize
        this.m_winValueLabel.updateRenderData(true);
        const uiTransform = this.m_winValueLabel.node.getComponent(UITransform);
        const textWidth = uiTransform.contentSize.width;

        // 使用快取的 Camera 引用
        const cam = this.getCachedCamera();
        if (!cam) return 0;

        const orthoH = cam.orthoHeight;
        const aspect = cam.camera.aspect || (view.getVisibleSize().width / view.getVisibleSize().height);
        const screenW = orthoH * aspect * 2;
        const margin = screenW * 0.075;

        const camX = cam.node.worldPosition.x;
        const leftBound = camX - screenW / 2 + margin;
        const rightBound = camX + screenW / 2 - margin;

        const worldX = this.node.worldPosition.x;
        const leftEdge = worldX - anchorX * textWidth;
        const rightEdge = worldX + (1 - anchorX) * textWidth;

        let offsetX = 0;
        if (leftEdge < leftBound) {
            offsetX = leftBound - leftEdge;
        } else if (rightEdge > rightBound) {
            offsetX = rightBound - rightEdge;
        }
        return offsetX;
    }

    /**@ch 顯示文字靜止不消失，從大縮到正常 + 淡入*/
    public async ShowStatic(text: string, isLeft: boolean) {
        this.m_winValueLabel.string = text;
        this.m_winValueLabel.node.active = true;
        this.m_winValueLabel.node.getComponent(UITransform).anchorX = 0.5;

        const offsetX = this.getClampedX();
        const offsetY = 50;
        this.m_winValueLabel.node.setPosition(offsetX, offsetY, 0);
        this.syncShadowSize();

        let opacity = this.m_winValueLabel.node.getComponent(UIOpacity);
        if (!opacity) { opacity = this.m_winValueLabel.node.addComponent(UIOpacity); }
        opacity.opacity = 0;

        this.m_winValueLabel.node.setScale(2, 2, 2);
        await new Promise<void>((resolve) => {
            tween(this.m_winValueLabel.node)
                .to(0.2, { scale: MultiplyFlyUI.SCALE_ONE })
                .call(() => resolve())
                .start();
            tween(opacity)
                .to(0.2, { opacity: 255 })
                .start();
        });
    }

    /**@ch 更新文字後往上飛離，移動中途切換為結果數字（根據 resultValue/bet 倍率選 label）*/
    public async UpdateAndFlyUp(text: string, isLeft: boolean = true, resultText?: string, resultValue?: number, bet?: number) {
        // 切 anchorX=0 前記錄原文字左邊緣位置，切完後補償使左邊不動
        this.m_winValueLabel.updateRenderData(true);
        const uiTransform = this.m_winValueLabel.node.getComponent(UITransform);
        const oldWidth = uiTransform.contentSize.width;
        const oldAnchorX = uiTransform.anchorX;
        const oldPos = this.m_winValueLabel.node.position;
        const oldLeftX = oldPos.x - oldAnchorX * oldWidth;

        this.m_winValueLabel.string = text;
        uiTransform.anchorX = 0;
        this.m_winValueLabel.updateRenderData(true);
        const newWidth = uiTransform.contentSize.width;

        // 左邊起點不變，只往右長；碰右邊界再推回
        let targetX = oldLeftX;
        const offsetX = this.getClampedX(0);
        if (offsetX < 0) targetX += offsetX;

        const offsetY = oldPos.y;
        this.m_winValueLabel.node.setPosition(targetX, offsetY, 0);
        this.syncShadowSize();

        let opacity = this.m_winValueLabel.node.getComponent(UIOpacity);
        if (!opacity) { opacity = this.m_winValueLabel.node.addComponent(UIOpacity); }
        opacity.opacity = 255;

        const flyUpDistance = 15;
        const flyDuration = 0.5;
        const shrinkDuration = 0.15;
        const growDuration = 0.15;

        // 重置 activeResultLabel
        this._activeResultLabel = null;

        // 非阻塞：往上飛 → 算式縮小淡出 → 結果放大淡入 → 淡出消失
        this._flyDeltaVec3.set(0, flyUpDistance, 0);
        tween(this.m_winValueLabel.node)
            .by(flyDuration, { position: this._flyDeltaVec3 }, { easing: 'cubicOut' })
            .call(() => {
                // 飛到頂：切回置中再縮小（避免往左角收）
                uiTransform.anchorX = 0.5;
                this.m_winValueLabel.updateRenderData(true);
                const curW = uiTransform.contentSize.width;
                const curPos = this.m_winValueLabel.node.position;
                // anchorX 0→0.5 補償：原本左邊緣位置 + 半寬 = 新中心位置
                this.m_winValueLabel.node.setPosition(curPos.x + curW * 0.5, curPos.y, 0);
                this.syncShadowSize();
            })
            // 飛到頂：算式縮小淡出
            .to(shrinkDuration, { scale: MultiplyFlyUI.SCALE_SHRINK })
            .call(() => {
                // 切成結果數字：根據倍率選用對應 label
                if (resultText) {
                    const targetLabel = this.getResultLabel(resultValue || 0, bet || 0);
                    if (targetLabel !== this.m_winValueLabel) {
                        // 切換到另一個 label
                        this.m_winValueLabel.node.active = false;
                        targetLabel.node.active = true;
                        targetLabel.string = resultText;
                        targetLabel.node.getComponent(UITransform).anchorX = 0.5;
                        const curPos = this.m_winValueLabel.node.position;
                        targetLabel.node.setPosition(curPos.x, curPos.y, 0);
                        targetLabel.node.setScale(0.3, 0.3, 0.3);
                        this._activeResultLabel = targetLabel;
                    } else {
                        this.m_winValueLabel.string = resultText;
                        this.m_winValueLabel.node.getComponent(UITransform).anchorX = 0.5;
                        const curPos = this.m_winValueLabel.node.position;
                        const clampX = this.getClampedX(0.5);
                        this.m_winValueLabel.node.setPosition(clampX || curPos.x, curPos.y, 0);
                        this.m_winValueLabel.node.setScale(0.3, 0.3, 0.3);
                    }
                    this.syncShadowSize();
                }

                // 結果放大淡入 → 停留 → 淡出（作用在正確的 node）
                const resultNode = this._activeResultLabel ? this._activeResultLabel.node : this.m_winValueLabel.node;
                let resultOpacity = resultNode.getComponent(UIOpacity);
                if (!resultOpacity) { resultOpacity = resultNode.addComponent(UIOpacity); }
                resultOpacity.opacity = 0;

                const finalScale = this.getResultScale(resultValue || 0, bet || 0);

                // Shadow 也要跟結果同步放大
                if (this.m_shadow) {
                    this.m_shadow.setScale(0.3, 0.3, 0.3);
                    let shadowOpacity = this.m_shadow.getComponent(UIOpacity);
                    if (!shadowOpacity) { shadowOpacity = this.m_shadow.addComponent(UIOpacity); }
                    shadowOpacity.opacity = 0;

                    // Shadow 跟結果同步放大 + 淡入
                    this._dynamicScaleVec3.set(finalScale, finalScale, finalScale);
                    tween(this.m_shadow)
                        .to(growDuration, { scale: this._dynamicScaleVec3 })
                        .start();
                    tween(shadowOpacity)
                        .to(growDuration, { opacity: 255 })
                        .start();
                }

                tween(resultNode)
                    .to(growDuration, { scale: this._dynamicScaleVec3 })
                    .delay(0.5)
                    .call(() => {
                        // 最終淡出：結果 + shadow 同步
                        const fadeDuration = 0.4;
                        tween(resultOpacity)
                            .to(fadeDuration, { opacity: 0 })
                            .call(() => {
                                this.resetAllLabels();
                            })
                            .start();
                        if (this.m_shadow) {
                            let shadowOp = this.m_shadow.getComponent(UIOpacity);
                            if (shadowOp) {
                                tween(shadowOp)
                                    .to(fadeDuration, { opacity: 0 })
                                    .start();
                            }
                        }
                    })
                    .start();

                tween(resultOpacity)
                    .to(growDuration, { opacity: 255 })
                    .start();
            })
            .start();

        // 算式 label 的透明度：飛行時保持 → 縮小同時淡出
        tween(opacity)
            .delay(flyDuration)
            .to(shrinkDuration, { opacity: 0 })
            .start();
    }

    /**@ch 重置所有 label 到初始狀態（UpdateAndFlyUp 結束時呼叫）*/
    private resetAllLabels(): void {
        this.m_winValueLabel.node.setPosition(0, 0, 0);
        this.m_winValueLabel.node.setScale(1, 1, 1);
        this.m_winValueLabel.node.active = false;
        let op = this.m_winValueLabel.node.getComponent(UIOpacity);
        if (op) op.opacity = 255;

        if (this.m_winValueLabel_10x) {
            this.m_winValueLabel_10x.node.setPosition(0, 0, 0);
            this.m_winValueLabel_10x.node.setScale(1, 1, 1);
            this.m_winValueLabel_10x.node.active = false;
            let op10 = this.m_winValueLabel_10x.node.getComponent(UIOpacity);
            if (op10) op10.opacity = 255;
        }
        if (this.m_winValueLabel_25x) {
            this.m_winValueLabel_25x.node.setPosition(0, 0, 0);
            this.m_winValueLabel_25x.node.setScale(1, 1, 1);
            this.m_winValueLabel_25x.node.active = false;
            let op25 = this.m_winValueLabel_25x.node.getComponent(UIOpacity);
            if (op25) op25.opacity = 255;
        }
        // 重置 shadow 透明度 + scale
        if (this.m_shadow) {
            this.m_shadow.setScale(1, 1, 1);
            let shadowOp = this.m_shadow.getComponent(UIOpacity);
            if (shadowOp) shadowOp.opacity = 255;
        }
        this._activeResultLabel = null;
    }

    /**@ch 顯示文字 → 停留 → 原地淡出*/
    public async ShowAndFlyUp(text: string, isLeft: boolean) {
        this.m_winValueLabel.string = text;
        this.m_winValueLabel.node.active = true;
        this.m_winValueLabel.node.getComponent(UITransform).anchorX = 0.5;

        const offsetX = this.getClampedX();
        const offsetY = 50;
        this.m_winValueLabel.node.setPosition(offsetX, offsetY, 0);
        this.syncShadowSize();
        this.m_winValueLabel.node.setScale(2, 2, 2);

        let opacity = this.m_winValueLabel.node.getComponent(UIOpacity);
        if (!opacity) { opacity = this.m_winValueLabel.node.addComponent(UIOpacity); }
        opacity.opacity = 0;

        await new Promise<void>((resolve) => {
            tween(this.m_winValueLabel.node)
                .delay(0.2)
                .to(0.1, { scale: MultiplyFlyUI.SCALE_ONE })
                .start();
            tween(opacity)
                .delay(0.2)
                .to(0.1, { opacity: 255 })
                .delay(0.25)
                .to(0.15, { opacity: 0 })
                .call(() => {
                    this.m_winValueLabel.node.setPosition(0, 0, 0);
                    this.m_winValueLabel.node.active = false;
                    // 重置 shadow 透明度
                    if (this.m_shadow) {
                        let shadowOp = this.m_shadow.getComponent(UIOpacity);
                        if (shadowOp) shadowOp.opacity = 255;
                    }
                    resolve();
                })
                .start();
            // Shadow 同步淡出
            if (this.m_shadow) {
                let shadowOpacity = this.m_shadow.getComponent(UIOpacity);
                if (!shadowOpacity) { shadowOpacity = this.m_shadow.addComponent(UIOpacity); }
                tween(shadowOpacity)
                    .delay(0.2 + 0.1 + 0.25)  // 跟 label 淡出同步
                    .to(0.15, { opacity: 0 })
                    .start();
            }
        });
    }

    // 保留舊方法相容性（若有其他地方呼叫）
    public SetWinValue(winValue: string): void {
        this.m_winValueLabel.string = winValue.toString();
    }

    public async ShowWinValue(isLeft: boolean) {
        await this.ShowAndFlyUp(this.m_winValueLabel.string, isLeft);
    }
}

