    /**@ch 根據累計數播 Scatter 停輪音效*/
    private PlayScatterStopSound(count: number): void {
        let clipName = '';
        if (this.m_gameView.IsFreeGame) {
            clipName = 'FG_Scatter_stop';
            AudioManager.Play(AudioManager.AudioClips.FG_Scatter_stop);
