2	import { BaseSpine } from './BaseSpine';
3	import { Define } from 'db://astarte-framework/utilis';
4	const { ccclass, property } = _decorator;
5	
6	@ccclass('InLoopOutSpine')
7	export class InLoopOutSpine extends BaseSpine {
8	    @property({
9	        type: String,
10	        tooltip: "進場動畫名稱"
11	    })
12	    private m_enterAnimationName: string = "In";
13	
14	    @property({
15	        type: String,
16	        tooltip: "循環動畫名稱"
17	    })
18	    private m_loopAnimationName: string = "Loop";
19	
20	    @property({
21	        type: String,
22	        tooltip: "退場動畫名稱"
23	    })
24	    private m_exitAnimationName: string = "Out";
25	
26	    /**@ch 是否正在播放 */
27	    private m_isPlaying: boolean = false;
28	
29	    /**
30	     * @ch 停止 Spine 動畫
31	     * @returns {void}
32	     */
33	    Stop()
34	    {
35	        super.Stop();
36	        this.m_isPlaying = false;
37	    }
38	
39	    /**
40	     * @ch 播放進場動畫
41	     * @param trackIdx 軌道索引
42	     * @param enterFinishCallback 進場動畫完成後回調
43	     * @param isAutoStop 是否自動停止 預設為true
44	     * 如果isAutoStop為true，則播放進場動畫並等待進場動畫完成後播放循環動畫，並在循環動畫完成後播放退場動畫
45	     * 如果isAutoStop為false，則播放進場動畫並等待進場動畫完成後播放循環動畫，並不會播放退場動畫
46	     * @param eventCb 動畫事件回調
47	     * @returns 
48	     */
49	    async PlayInLoop(trackIdx: number = 0, enterFinishCallback: () => void, isAutoStop: boolean = true, eventCb?: (eventName: string) => void) : Promise<void>
50	    {
51	        if (this.m_isPlaying) return;
52	        this.m_isPlaying = true;
53	        this.SetNodeActivity(true);
54	        this.SetSpineNodeActivity(true);
55	        await this.PlayAnimation(this.m_enterAnimationName, this.m_spine, false, 1, eventCb, trackIdx);
56	        enterFinishCallback?.();
57	        await this.PlayAnimation(this.m_loopAnimationName, this.m_spine, !isAutoStop, 1, eventCb, trackIdx);
58	        if (isAutoStop)
59	        {
60	            await this.PlayOut(trackIdx);
61	        }
62	    }
63	
64	    /**
65	     * @ch 播放 進場In → 循環Loop(停留 holdSec 秒) → 退場Out → 隱藏。
66	     * In 播完即觸發 enterFinishCallback（供外部流程續行），整段播完後才 resolve。
67	     * @param holdSec Loop 停留秒數
68	     * @param enterFinishCallback In 播完後回調
69	     * @param trackIdx 軌道索引
70	     * @param eventCb 動畫事件回調
71	     */
72	    async PlayInHoldOut(holdSec: number, enterFinishCallback?: () => void, waitDuringLoop?: () => Promise<void>, trackIdx: number = 0, eventCb?: (eventName: string) => void) : Promise<void>
73	    {
74	        if (this.m_isPlaying) return;
75	        this.m_isPlaying = true;
76	        this.SetNodeActivity(true);
77	        this.SetSpineNodeActivity(true);
78	        // 進場 In（播完才往下）
79	        await this.PlayAnimation(this.m_enterAnimationName, this.m_spine, false, 1, eventCb, trackIdx);
80	        enterFinishCallback?.();
81	        // 循環 Loop（loop=true，不 await）→ 先等 waitDuringLoop（例如數字跑完）→ 再停 holdSec 秒
82	        this.PlayAnimation(this.m_loopAnimationName, this.m_spine, true, 1, eventCb, trackIdx);
83	        if (waitDuringLoop) await waitDuringLoop();
84	        await Define.Wait(this, holdSec);
85	        // 退場 Out（播完才往下）
86	        await this.PlayAnimation(this.m_exitAnimationName, this.m_spine, false, 1, eventCb, trackIdx);
87	        this.SetNodeActivity(false);
88	        this.SetSpineNodeActivity(false);
89	        this.m_isPlaying = false;
90	    }
91	
92	    /**
93	     * @ch 播放退場動畫
94	     * @param trackIdx 軌道索引
95	     * @param outPlayDuration 退場動畫播放時間（秒）
96	     * 如果退場動畫播放時間大於0，則播放退場動畫並等待退場動畫播放時間後停止
97	     * 如果退場動畫播放時間小於0，則播放退場動畫並等待動畫完成後停止
98	     * @param outStopCallback 退場動畫完成後回調
99	     * @returns 
100	     */
101	    async PlayOut(trackIdx: number = 0, outPlayDuration: number = -1, outStopCallback: () => void = () => {}, eventCb?: (eventName: string) => void) : Promise<void>
