import { _decorator, Component, Label, log, warn, sp, Sprite, SpriteAtlas } from "cc";
import SpineKit from "db://astarte-framework/Component/Spine/SpineKit";
import { newBottombarManager } from "db://astarte-framework/Managers";
import { tools } from "db://astarte-framework/utilis";
import { AudioManager } from "../Audio/AudioManager";

const { ccclass, property } = _decorator;

const ANIM_NAME = {
    FG_MoreSpins_Start: "FG_MoreSpins_Start",
    FG_MoreSpins_Loop: "FG_MoreSpins_Loop",
    FG_MoreSpins_End: "FG_MoreSpins_End",
    FG_Multiple_Start: "FG_Multiple_Start",
    FG_Multiple_Loop: "FG_Multiple_Loop",
    FG_Multiple_End: "FG_Multiple_End",
    FG_MoreSpins_plus: "FG_MoreSpins_plus",
};

@ccclass( "PopupSpine" )
export class PopupSpine extends Component
{
    @property( { type: sp.Skeleton, tooltip: "Spine" } )
    private m_spine: sp.Skeleton = null;

    @property( { type: Sprite, tooltip: "贏得 Txt" } )
    private m_winTxt: Sprite = null;

    @property( { type: Label, tooltip: "贏分數字" } )
    private m_winLabel: Label = null;

    @property( { type: Sprite, tooltip: "FREE SPIN Txt" } )
    private m_freeSpinTxt: Sprite = null;

    @property( { type: Label, tooltip: "FG 加局數" } )
    private m_roundLabel: Label = null;

    SetTxt( atlas: SpriteAtlas )
    {
        if ( this.m_winTxt ) this.m_winTxt.spriteFrame = atlas.getSpriteFrame( "you won" );
        if ( this.m_freeSpinTxt ) this.m_freeSpinTxt.spriteFrame = atlas.getSpriteFrame( "IN FREE SPIN" );
    }

    SetNodeActivity( active: boolean )
    {
        this.node.active = active;
    }

    GetWinLabelWorldPosition()
    {
        return this.m_winLabel.node.getWorldPosition();
    }



    /** 乘倍面板：顯示贏分 Start → Loop */
    ShowMultipleDeclare( win: number )
    {
        this.SetNodeActivity( true );
        this.m_winLabel.string = tools.FormatNumberThousands( tools.strip( win ), tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT );
        AudioManager.Play( AudioManager.AudioClips.FG_Win_on );
        return SpineKit.PlayAnimation( this.m_spine, ANIM_NAME.FG_MoreSpins_Start, false )
            .then( () =>
            {
                SpineKit.PlayAnimation( this.m_spine, ANIM_NAME.FG_MoreSpins_Loop, true );
            } );
    }



    /** 加局面板：顯示局數 Start → Loop */
    ShowMoreSpinsDeclare( round: number )
    {
        this.SetNodeActivity( true );
        this.m_roundLabel.string = round.toString();
        if ( !this.m_spine || !this.m_spine.skeletonData ) {
            warn( "[PopupSpine] WARNING: spine or skeletonData is null, skip ShowMoreSpinsDeclare" );
            return Promise.resolve();
        }
        const rd = this.m_spine.skeletonData.getRuntimeData();
        if ( !rd || !rd.animations.find( (a: any) => a.name === ANIM_NAME.FG_Multiple_Start ) ) {
            warn( `[PopupSpine] WARNING: animation "${ANIM_NAME.FG_Multiple_Start}" not found, skip` );
            return Promise.resolve();
        }
        return SpineKit.PlayAnimation( this.m_spine, ANIM_NAME.FG_Multiple_Start, false )
            .then( () =>
            {
                SpineKit.PlayAnimation( this.m_spine, ANIM_NAME.FG_Multiple_Loop, true );
            } );
    }

    SetRound( round: number )
    {
        this.m_roundLabel.string = round.toString();
    }

    PlayMoreSpinsEnd()
    {
        if ( !this.m_spine || !this.m_spine.skeletonData ) {
            warn( "[PopupSpine] WARNING: spine or skeletonData is null, skip PlayMoreSpinsEnd" );
            this.SetNodeActivity( false );
            return Promise.resolve();
        }
        const rd = this.m_spine.skeletonData.getRuntimeData();
        if ( !rd || !rd.animations.find( (a: any) => a.name === ANIM_NAME.FG_Multiple_End ) ) {
            warn( `[PopupSpine] WARNING: animation "${ANIM_NAME.FG_Multiple_End}" not found, skip` );
            this.SetNodeActivity( false );
            return Promise.resolve();
        }
        return SpineKit.PlayAnimation( this.m_spine, ANIM_NAME.FG_Multiple_End, false )
            .then( () =>
            {
                this.SetNodeActivity( false );
            } );
    }
}

