import { _decorator, Component, sp } from 'cc';
import { localeStringManager } from 'db://astarte-framework/Managers';
const { ccclass } = _decorator;

@ccclass('SpineMultiLangTool')
export class SpineMultiLangTool extends Component {
    private m_Spine: sp.Skeleton = null;

    /**
     * @ch 自動抓取物件上Spine
     */
    protected onLoad(): void {
        if (this.m_Spine === null) {
            this.m_Spine = this.getComponent(sp.Skeleton);
        }
        this.SetLanguage(localeStringManager.CurrLang);
    }

    /**
     * @ch 設置語言
     * @param language 語言
     */
    public SetLanguage(language: string): void {
        let lang = language;
        switch (language) {
            case 'tw':
                lang = 'CHT';
                break;
            case 'cn':
                lang = 'CHS';
                break;
            case 'en':
                lang = 'EN';
            case 'it':
                lang = 'IT';
                break;
            case 'th':
                lang = 'TH';
                break;
            default:
                lang = 'EN';
                break;
        }
        if (this.m_Spine) {
            this.m_Spine.setSkin(lang);
            this.m_Spine.setSlotsToSetupPose();
        }
    }

    /**
     * @ch 更新語言
     */
    public UpdateLanguage(): void {
        this.SetLanguage(localeStringManager.CurrLang);
    }
}

