124	    /**
125	     * 格式化數字為帶有 M/K 後綴的顯示格式
126	     * @param value 要格式化的數值
127	     * @param millionThreshold 百萬閾值，預設為 Game_Define.MILLION
128	     * @param thousandThreshold 千閾值，預設為 Game_Define.THOUSAND
129	     * @param decimalPlaces 小數點後顯示的位數，預設為 2
130	     * @returns 格式化後的顯示字串
131	     */
132	    static FormatNumberWithSuffix(value: number, millionThreshold?: number, thousandThreshold?: number, decimalPlaces: number = 2): string {
133	        // 使用預設閾值或傳入的閾值
134	        const million = millionThreshold || Game_Define.MILLION;
135	        const thousand = thousandThreshold || Game_Define.THOUSAND;
136	        
137	        let showString = "";
138	        
139	        if (value >= million) {
140	            // 處理百萬級別
141	            let tempString = tools.divide(value, million).toString();
142	            let pos = tempString.indexOf(".");
143	            
144	            if (pos === -1) {
145	                pos = tempString.length;
146	            } else {
147	                // 根據自定義的小數位數計算位置
148	                pos = pos + decimalPlaces + 1 > tempString.length ? tempString.length : pos + decimalPlaces + 1;
149	            }
150	            
151	            showString = tempString.substring(0, pos) + "M";
152	        } else if (value >= thousand) {
153	            // 處理千級別
154	            let tempString = tools.divide(value, thousand).toString();
155	            let pos = tempString.indexOf(".");
156	            
157	            if (pos === -1) {
158	                pos = tempString.length;
159	            } else {
160	                // 根據自定義的小數位數計算位置
161	                pos = pos + decimalPlaces + 1 > tempString.length ? tempString.length : pos + decimalPlaces + 1;
162	            }
163	            
164	            showString = tempString.substring(0, pos) + "K";
165	        } else {
166	            // 小於千的數值直接顯示
167	            showString = value.toString();
168	        }
169	        
170	        return showString;
171	    }
