185	    /**
186	     * @ch 格式化數字為自訂縮寫格式，當數字超過最大顯示位數時依序嘗試 K → M → B 縮寫
187	     * @param value 要處理的數字（會先經過 newBottombarManager.GetDisplayValue 轉換）
188	     * @param maxDigits 控制最大顯示位數（純數字字元數，不含逗號和小數點）
189	     * @param decimalPlaces 小數點最多顯示位數（使用無條件捨去）
190	     * @returns 格式化後的字串（可能包含 K/M/B 後綴）
191	     * @example
192	     * // 原數字不超過 maxDigits，直接顯示
193	     * FormatNumberWithCustomAbbreviation(12345, 5, 2)        // "12,345" (5位數字，符合限制)
194	     *
195	     * // 原數字超過 maxDigits，用 K 縮寫後符合
196	     * FormatNumberWithCustomAbbreviation(123456, 5, 2)       // "123.45K" (原本6位 → K後5位)
197	     *
198	     * // K 縮寫後仍超過，改用 M 縮寫
199	     * FormatNumberWithCustomAbbreviation(12345678, 5, 2)     // "12.34M" (K後7位 → M後4位)
200	     *
201	     * // M 縮寫後仍超過，改用 B 縮寫
202	     * FormatNumberWithCustomAbbreviation(12345678901, 5, 2)  // "12.34B" (M後7位 → B後4位)
203	     */
204	    static FormatNumberWithCustomAbbreviation(
205	        value: number,
206	        maxDigits: number,
207	        decimalPlaces: number
208	    ): string {
209	        // 先透過 newBottombarManager 轉換數值（處理 bet 倍率等邏輯）
210	        const displayValue = newBottombarManager.GetDisplayValue(value);
211	
212	        // 格式化原始數字（會自動移除尾隨 0）
213	        const formattedFull = tools.FormatNumberThousands(displayValue, tools.FORMAT_NUMBER_TYPE.DEFINE_DOT_NONE_ZERO);
214	
215	        // 計算純數字字元數（移除小數點和逗號）
216	        const digitCount = formattedFull.replace(/[,\.]/g, '').length;
217	
218	        // 如果原始數字不超過限制，直接回傳
219	        if (digitCount <= maxDigits) {
220	            return formattedFull;
221	        }
222	
223	        // 依序嘗試縮寫單位：K → M → B
224	        const units = [
225	            { suffix: 'K', divisor: 1_000 },
226	            { suffix: 'M', divisor: 1_000_000 },
227	            { suffix: 'B', divisor: 1_000_000_000 }
228	        ];
229	
230	        for (let i = 0; i < units.length; i++) {
231	            const { suffix, divisor } = units[i];
232	            const abbreviatedValue = displayValue / divisor;
233	
234	            // 使用無條件捨去保留指定的小數位數
235	            const multiplier = Math.pow(10, decimalPlaces);
236	            const floored = Math.floor(abbreviatedValue * multiplier) / multiplier;
237	
238	            // 格式化縮寫後的數字
239	            const formatted = tools.FormatNumberThousands(floored, tools.FORMAT_NUMBER_TYPE.DEFINE_DOT_NONE_ZERO);
240	            const digits = formatted.replace(/[,\.]/g, '').length;
241	
242	            // 如果縮寫後符合位數限制，就使用此單位
243	            // 或者已經是最後一個單位（B），無論如何都使用
244	            if (digits <= maxDigits || i === units.length - 1) {
245	                return formatted + suffix;
246	            }
247	            // 否則繼續嘗試下一個更大的單位
248	        }
249	
250	        // 理論上不會執行到這裡
251	        return formattedFull;
252	    }
