666	                    const currentPos = bezierCurve.GetPosition(ratio);
667	                    flyNode.setPosition(currentPos);
668	                }
669	            })
670	            .call(() => {
671	                flyNode.setPosition(endLocalPosition);
672	                if (callback) {
673	                    callback();
674	                }
675	                resolveDone();
676	            });
677	
678	        return { tween: tw, done };
679	    }
680	
681	    /**
682	     * 根據一維位置索引取得行列座標 (各遊戲不同)
683	     * @param position 一維位置索引 (0-14)
684	     * @returns {col: number, row: number}
685	     */
686	    static GetColRowFromPosition(position: number): { col: number, row: number } {
687	        if (!this.m_gameView) {
688	            console.error(`GetColRowFromPosition: GameView is not initialized`);
689	            return { col: 0, row: 0 };
690	        }
691	        return this.m_gameView.SlotReels.GetColRowFromPosition(position);
692	    }
693	
694	    /**
695	     * 根據行列座標取得一維位置索引 (各遊戲不同)
696	     * @param col 列
697	     * @param row 行
698	     * @returns 一維位置索引
699	     */
700	    static GetPositionFromColRow(col: number, row: number): number {
701	        if (!this.m_gameView) {
702	            console.error(`GetPositionFromColRow: GameView is not initialized`);
703	            return 0;
704	        }
705	        return this.m_gameView.SlotReels.GetPositionFromColRow(col, row);
706	    }
707	
708	    /**
709		 * 將 IRoundInfo.FeaturePosQueue 轉為有資料的 FeaturePosQueueType 與對應位置們
710		 * - 伺服器位置編碼解碼規則：col = floor(n / Game_Define.ROW), row = n % Game_Define.ROW
711		 * - 僅輸出有資料的類型
712		 * @param featurePosQueue 位置佇列（IRoundInfo.FeaturePosQueue）
713		 * @returns 僅包含有資料的型別與位置清單
714		 */
715		static ParseFeaturePosQueue(
716			featurePosQueue: Array<{ Data?: number[] }>
717		): Array<{ type: FeaturePosQueueType; positions: Array<{ col: number; row: number }> }>
718		{
719			const result: Array<{ type: FeaturePosQueueType; positions: Array<{ col: number; row: number }> }> = [];
720			
721			if (!featurePosQueue || !Array.isArray(featurePosQueue)) {
722				return result;
723			}
724			
725			for (let typeIndex = 0; typeIndex < featurePosQueue.length; typeIndex++) {
726				const queueItem = featurePosQueue[typeIndex];
727				
728				// 只處理有 Data 且不為空的項目
729				if (!queueItem || !queueItem.Data || queueItem.Data.length === 0) {
730					continue;
731				}
732				
733				// 解碼位置資訊
734				const positions: Array<{ col: number; row: number }> = [];
735				for (const encodedPos of queueItem.Data) {
736	                const { col, row } = this.GetColRowFromPosition(encodedPos);
737					positions.push({ col, row });
738				}
739				
740				// 將該類型的資料加入結果
741				result.push({
742					type: typeIndex as FeaturePosQueueType,
743					positions
744				});
745			}
746			
747			return result;
748		}
749	
750	    /**
751	     * 取得目前語言
752	     * @returns 目前語言
753	     */
754	    static GetLanguage(): string {
755	        return localeStringManager.CurrLang;
756	    }
757	    
758		/**
759		 * 解析贏分閾值
760		 * @param value 贏分閾值
761		 * @returns 贏分閾值，如果無效則返回 null
762		 */
763		static ParseWinThreshold(value: unknown): number | null {
764			const num = Number(value);
765			if (!Number.isFinite(num) || num <= 0) {
766				return null;
767			}
768			return num;
769		}
770	
771		/**
772		 * 根據總贏分計算贏分類型
773		 * @param totalWin 總贏分
774		 * @returns 贏分類型
775		 */
776		static GetWinType(totalWin: number): WinType {
777			if (totalWin <= 0) {
778				return WinType.NoWin;
779			}
780	
781			const config: {
782				SUPER_WIN_MIN?: number;
783				MEGA_WIN_MIN?: number;
784				BIG_WIN_MIN?: number;
785				YOU_WIN_MIN?: number;
786			} = Game_Define.BigWinWinRule ?? {};
787			const superWinMin = this.ParseWinThreshold(config?.SUPER_WIN_MIN);
788			const megaWinMin = this.ParseWinThreshold(config?.MEGA_WIN_MIN);
789			const bigWinMin = this.ParseWinThreshold(config?.BIG_WIN_MIN);
790			const youWinMin = this.ParseWinThreshold(config?.YOU_WIN_MIN) ?? 0;
791	
792			if (superWinMin !== null && totalWin >= superWinMin) {
793				return WinType.SuperWin;
794			}
795			if (megaWinMin !== null && totalWin >= megaWinMin) {
796				return WinType.MegaWin;
797			}
798			if (bigWinMin !== null && totalWin >= bigWinMin) {
799				return WinType.BigWin;
800			}
801			if (totalWin >= youWinMin) {
802				return WinType.YouWin;
803			}
804			return WinType.NormalWin;
805		}
806	}
