import { _decorator, Vec3, Node, SpriteFrame, SpriteAtlas, tween, Tween, log } from 'cc';
import GameView from '../GameView';
import { Define, tools } from 'db://astarte-framework/utilis';
import { localeStringManager, newBottombarManager } from 'db://astarte-framework/Managers';
import { CommonEffect } from './CommonEffect';
import Game_Define, { FeaturePosQueueType, WinType } from '../Game_Define';
const { ccclass, property } = _decorator;

/**
 * 堆疊節點資料
 */
export class PopupNodeData {
    /**@ch 原本位置 */
    WorldPosition: Vec3;

    /**@ch 原本本地座標 */
    LocalPosition: Vec3;

    /**@ch 是否保持原來位置*/
    IsKeepWorldPosition: boolean;

    /**@ch 原本父節點 */
    OriginParent: Node;

    /**@ch 原本位置的兄弟索引 */
    SiblingIndex: number;

    /**@ch 我的節點 */
    MyNode: Node;
}

@ccclass('Common')
export class Common  {

    static m_gameView: GameView = null;
    static Init(gameView: GameView)
    {
        this.m_gameView = gameView;
    }

    static GetGameView(): GameView | null {
        return this.m_gameView;
    }

    /**
     * 檢查指定位置是否有效
     * @param col 列
     * @param row 行
     * @returns 是否有效
     */
    static IsValidPosition(col: number, row: number): boolean {
        return col >= 0 && col < Game_Define.COL && row >= 0 && row < Game_Define.ROW;
    }

    /**
     * 將節點推入堆疊
     * @param node 要推入的節點
     * @param parent 要推入的父節點
     * @param isUseSymbolLocalPosition 是否使用符號本地座標 (0, 0, 0)
     * @returns 推入的節點資料
     */
    static PushNode(node: Node, parent: Node, isKeepWorldPosition: boolean = true): PopupNodeData {
        const popupNodeData = new PopupNodeData();
        popupNodeData.WorldPosition = node.getWorldPosition();
        popupNodeData.LocalPosition = node.getPosition();
        popupNodeData.IsKeepWorldPosition = isKeepWorldPosition;
        popupNodeData.OriginParent = node.parent;
        //popupNodeData.SiblingIndex = node.getSiblingIndex();
        popupNodeData.MyNode = node;
        log(`${node.name} push to ${node.getSiblingIndex()}`);
        //parent.addChild(node);
        node.setParent(parent,isKeepWorldPosition);
        return popupNodeData;
    }

    /**
     * 從堆疊中取出節點
     * @param popupNodeData 要從堆疊中取出的節點資料
     * @returns 取出的節點
     */
    static PopNode(popupNodeData: PopupNodeData): Node {
        if (popupNodeData === null) {
            console.error("PopNode: popupNodeData is null");
            return null;
        }

        const node = popupNodeData.MyNode;
        node.setParent(popupNodeData.OriginParent,popupNodeData.IsKeepWorldPosition);
        //popupNodeData.OriginParent.addChild(node);
        log(`${node.name} push to ${popupNodeData.SiblingIndex}`);
        //node.setSiblingIndex(popupNodeData.SiblingIndex);
        /*
        if (popupNodeData.IsUseLocalPosition) {
            node.setPosition(popupNodeData.LocalPosition);
        } else {
            node.setWorldPosition(popupNodeData.WorldPosition);
        }*/
        return node;
    }

    /**
     * 載入Json檔案
     * @param filePath 檔案路徑
     * @returns 載入的資料
     */
    static LoadJsonFile = (filePath: string): Promise<any> => {
        return new Promise((resolve, reject) => {
            Define.GameBundle.load(filePath, (err: Error, jsonAsset: any) => {
                if (err) {
                    reject(err);
                    return;
                }

                try {
                    const data = jsonAsset.json || jsonAsset;
                    resolve(data);
                } catch (parseError) {
                    reject(parseError);
                }
            });
        });
    };

    /**
     * 格式化數字為帶有 M/K 後綴的顯示格式
     * @param value 要格式化的數值
     * @param millionThreshold 百萬閾值，預設為 Game_Define.MILLION
     * @param thousandThreshold 千閾值，預設為 Game_Define.THOUSAND
     * @param decimalPlaces 小數點後顯示的位數，預設為 2
     * @returns 格式化後的顯示字串
     */
    static FormatNumberWithSuffix(value: number, millionThreshold?: number, thousandThreshold?: number, decimalPlaces: number = 2): string {
        // 使用預設閾值或傳入的閾值
        const million = millionThreshold || Game_Define.MILLION;
        const thousand = thousandThreshold || Game_Define.THOUSAND;

        let showString = "";

        if (value >= million) {
            // 處理百萬級別
            let tempString = tools.divide(value, million).toString();
            let pos = tempString.indexOf(".");

            if (pos === -1) {
                pos = tempString.length;
            } else {
                // 根據自定義的小數位數計算位置
                pos = pos + decimalPlaces + 1 > tempString.length ? tempString.length : pos + decimalPlaces + 1;
            }

            showString = tempString.substring(0, pos) + "M";
        } else if (value >= thousand) {
            // 處理千級別
            let tempString = tools.divide(value, thousand).toString();
            let pos = tempString.indexOf(".");

            if (pos === -1) {
                pos = tempString.length;
            } else {
                // 根據自定義的小數位數計算位置
                pos = pos + decimalPlaces + 1 > tempString.length ? tempString.length : pos + decimalPlaces + 1;
            }

            showString = tempString.substring(0, pos) + "K";
        } else {
            // 小於千的數值直接顯示
            showString = value.toString();
        }

        return showString;
    }

    /**
     * 格式化數字
     * @param value 要格式化的數字
     * @returns
     */
    static FormatNumber(value: number): string {
        return tools.FormatNumberThousands(
            newBottombarManager.GetDisplayValue(value),
            tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT
        );
    }

    /**
     * @ch 格式化數字為自訂縮寫格式，當數字超過最大顯示位數時依序嘗試 K → M → B 縮寫
     * @param value 要處理的數字（會先經過 newBottombarManager.GetDisplayValue 轉換）
     * @param maxDigits 控制最大顯示位數（純數字字元數，不含逗號和小數點）
     * @param decimalPlaces 小數點最多顯示位數（使用無條件捨去）
     * @returns 格式化後的字串（可能包含 K/M/B 後綴）
     * @example
     * // 原數字不超過 maxDigits，直接顯示
     * FormatNumberWithCustomAbbreviation(12345, 5, 2)        // "12,345" (5位數字，符合限制)
     *
     * // 原數字超過 maxDigits，用 K 縮寫後符合
     * FormatNumberWithCustomAbbreviation(123456, 5, 2)       // "123.45K" (原本6位 → K後5位)
     *
     * // K 縮寫後仍超過，改用 M 縮寫
     * FormatNumberWithCustomAbbreviation(12345678, 5, 2)     // "12.34M" (K後7位 → M後4位)
     *
     * // M 縮寫後仍超過，改用 B 縮寫
     * FormatNumberWithCustomAbbreviation(12345678901, 5, 2)  // "12.34B" (M後7位 → B後4位)
     */
    static FormatNumberWithCustomAbbreviation(
        value: number,
        maxDigits: number,
        decimalPlaces: number
    ): string {
        // 先透過 newBottombarManager 轉換數值（處理 bet 倍率等邏輯）
        const displayValue = newBottombarManager.GetDisplayValue(value);

        // 格式化原始數字（會自動移除尾隨 0）
        const formattedFull = tools.FormatNumberThousands(displayValue, tools.FORMAT_NUMBER_TYPE.DEFINE_DOT_NONE_ZERO);

        // 計算純數字字元數（移除小數點和逗號）
        const digitCount = formattedFull.replace(/[,\.]/g, '').length;

        // 如果原始數字不超過限制，直接回傳
        if (digitCount <= maxDigits) {
            return formattedFull;
        }

        // 依序嘗試縮寫單位：K → M → B
        const units = [
            { suffix: 'K', divisor: 1_000 },
            { suffix: 'M', divisor: 1_000_000 },
            { suffix: 'B', divisor: 1_000_000_000 }
        ];

        for (let i = 0; i < units.length; i++) {
            const { suffix, divisor } = units[i];
            const abbreviatedValue = displayValue / divisor;

            // 使用無條件捨去保留指定的小數位數
            const multiplier = Math.pow(10, decimalPlaces);
            const floored = Math.floor(abbreviatedValue * multiplier) / multiplier;

            // 格式化縮寫後的數字
            const formatted = tools.FormatNumberThousands(floored, tools.FORMAT_NUMBER_TYPE.DEFINE_DOT_NONE_ZERO);
            const digits = formatted.replace(/[,\.]/g, '').length;

            // 如果縮寫後符合位數限制，就使用此單位
            // 或者已經是最後一個單位（B），無論如何都使用
            if (digits <= maxDigits || i === units.length - 1) {
                return formatted + suffix;
            }
            // 否則繼續嘗試下一個更大的單位
        }

        // 理論上不會執行到這裡
        return formattedFull;
    }

    /**
     * 是否鎖定旋轉
     * @returns 是否鎖定
     */
    static IsLockOrientation(): boolean
    {
        if (this.m_gameView) {
            return this.m_gameView.IsLockRotation;
        }
        return false;
    }

    /**
     * 設定是否鎖定旋轉
     * @param isLock 是否鎖定
     */
    static SetLockOrientation(isLock: boolean)
    {
        if (this.m_gameView) {
            this.m_gameView.IsLockRotation = isLock;
        }
    }

    /**
     * 取得文字圖集中的圖片
     * @param spriteName 圖片名稱
     * @returns 圖片
     */
    static GetSpriteInCommonText(spriteName: string): SpriteFrame {
        let atlas: SpriteAtlas = localeStringManager.GetGameAtlas();
        return atlas ? atlas.getSpriteFrame(spriteName) : null;
    }

    /**
     * 直線移動動畫
     * @param flyNode 要移動的節點
     * @param startWorldPosition 起始世界座標
     * @param endWorldPosition 結束世界座標
     * @param duration 動畫持續時間（秒）
     * @param callback 完成回調函數
     * @returns Promise
     */
    static MoveTo(flyNode: Node, startWorldPosition: Vec3, endWorldPosition: Vec3, duration: number, callback?: () => void): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!flyNode || !flyNode.isValid) {
                console.warn("MoveTo: flyNode is null or invalid");
                if (callback) callback();
                resolve();
                return;
            }

            // 設定起始位置
            flyNode.setWorldPosition(startWorldPosition);

            // 建立直線移動動畫
            tween(flyNode)
                .to(duration, {
                    worldPosition: endWorldPosition
                })
                .call(() => {
                    // 確保最終位置正確
                    flyNode.setWorldPosition(endWorldPosition);

                    // 調用完成回調
                    if (callback) {
                        callback();
                    }

                    resolve();
                })
                .start();
        });
    }

    /**
     * 直線移動動畫（新版）
     * - 回傳可操作的 tween 與可 await 的 done Promise
     * - 不自動 .start()，由呼叫端決定何時開始
     */
    static MoveToWithTween(
        flyNode: Node,
        startWorldPosition: Vec3,
        endWorldPosition: Vec3,
        duration: number,
        callback?: () => void
    ): { tween: Tween<Node> | null; done: Promise<void> } {
        let resolveDone: () => void;
        const done = new Promise<void>((resolve) => { resolveDone = resolve; });

        if (!flyNode || !flyNode.isValid) {
            console.warn("MoveToWithTween: flyNode is null or invalid");
            if (callback) callback();
            // 立即完成
            resolveDone();
            return { tween: null, done };
        }

        // 設定起始位置
        flyNode.setWorldPosition(startWorldPosition);

        const tw = tween(flyNode)
            .to(duration, { worldPosition: endWorldPosition })
            .call(() => {
                flyNode.setWorldPosition(endWorldPosition);
                if (callback) {
                    callback();
                }
                resolveDone();
            });

        return { tween: tw, done };
    }

    /**
     * 貝茲曲線移動動畫
     * @param flyNode 要移動的節點
     * @param startWorldPosition 起始世界座標
     * @param endWorldPosition 結束世界座標
     * @param duration 動畫持續時間（秒）
     * @param callback 完成回調函數
     * @returns Promise
     */
    static BezierMoveTo(flyNode: Node, startWorldPosition: Vec3, endWorldPosition: Vec3, duration: number, callback?: () => void): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!flyNode || !flyNode.isValid) {
                console.warn("BezierMoveTo: flyNode is null or invalid");
                if (callback) callback();
                resolve();
                return;
            }

            // 計算控制點（在起始點和結束點之間的上方創建一個弧形路徑）
            const midX = (startWorldPosition.x + endWorldPosition.x) / 2;
            const midY = (startWorldPosition.y + endWorldPosition.y) / 2;

            // 計算高度偏移：基於起始點和結束點之間的距離
            const distance = Vec3.distance(startWorldPosition, endWorldPosition);
            const heightOffset = Math.max(100, distance * 0.3); // 最小100像素高度

            const controlPoint = new Vec3(midX, midY + heightOffset, 0);

            // 建立貝茲曲線物件（3階貝茲曲線：起始點、控制點、結束點）
            const bezierCurve = new CommonEffect.Bezier([startWorldPosition, controlPoint, endWorldPosition]);

            // 設定起始位置
            flyNode.setWorldPosition(startWorldPosition);

            // 使用臨時物件追蹤動畫進度
            const animationTarget = { progress: 0 };
            tween(animationTarget)
                .to(duration, { progress: 1 }, {
                    onUpdate: (target, ratio) => {
                        // 使用 CommonEffect.Bezier 計算當前位置
                        const currentPos = bezierCurve.GetPosition(ratio);
                        flyNode.setWorldPosition(currentPos);
                    }
                })
                .call(() => {
                    // 確保最終位置正確
                    flyNode.setWorldPosition(endWorldPosition);

                    // 調用完成回調
                    if (callback) {
                        callback();
                    }

                    resolve();
                })
                .start();
        });
    }

    /**
     * 貝茲曲線移動動畫（新版）
     * - 回傳可操作的 tween 與可 await 的 done Promise
     * - 不自動 .start()，由呼叫端決定何時開始
     */
    static BezierMoveToWithTween(
        flyNode: Node,
        startWorldPosition: Vec3,
        endWorldPosition: Vec3,
        duration: number,
        callback?: () => void
    ): { tween: Tween<{ progress: number }> | null; done: Promise<void> } {
        let resolveDone: () => void;
        const done = new Promise<void>((resolve) => { resolveDone = resolve; });

        if (!flyNode || !flyNode.isValid) {
            console.warn("BezierMoveToWithTween: flyNode is null or invalid");
            if (callback) callback();
            resolveDone();
            return { tween: null, done };
        }

        // 計算控制點（在起始點和結束點之間的上方創建一個弧形路徑）
        const midX = (startWorldPosition.x + endWorldPosition.x) / 2;
        const midY = (startWorldPosition.y + endWorldPosition.y) / 2;

        // 計算高度偏移：基於起始點和結束點之間的距離
        const distance = Vec3.distance(startWorldPosition, endWorldPosition);
        const heightOffset = Math.max(100, distance * 0.3); // 最小100像素高度

        const controlPoint = new Vec3(midX, midY + heightOffset, 0);

        // 建立貝茲曲線物件（3階貝茲曲線：起始點、控制點、結束點）
        const bezierCurve = new CommonEffect.Bezier([startWorldPosition, controlPoint, endWorldPosition]);

        // 設定起始位置
        flyNode.setWorldPosition(startWorldPosition);

        // 使用臨時物件追蹤動畫進度
        const animationTarget = { progress: 0 };
        const tw = tween(animationTarget)
            .to(duration, { progress: 1 }, {
                onUpdate: (target, ratio) => {
                    const currentPos = bezierCurve.GetPosition(ratio);
                    flyNode.setWorldPosition(currentPos);
                }
            })
            .call(() => {
                flyNode.setWorldPosition(endWorldPosition);
                if (callback) {
                    callback();
                }
                resolveDone();
            });

        return { tween: tw, done };
    }

    /**
     * 直線移動動畫（本地座標版本）
     * @param flyNode 要移動的節點
     * @param startLocalPosition 起始本地座標
     * @param endLocalPosition 結束本地座標
     * @param duration 動畫持續時間（秒）
     * @param callback 完成回調函數
     * @returns Promise
     */
    static MoveToLocalPosition(flyNode: Node, startLocalPosition: Vec3, endLocalPosition: Vec3, duration: number, callback?: () => void): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!flyNode || !flyNode.isValid) {
                console.warn("MoveToLocalPosition: flyNode is null or invalid");
                if (callback) callback();
                resolve();
                return;
            }

            // 設定起始位置
            flyNode.setPosition(startLocalPosition);

            // 建立直線移動動畫
            tween(flyNode)
                .to(duration, {
                    position: endLocalPosition
                })
                .call(() => {
                    // 確保最終位置正確
                    flyNode.setPosition(endLocalPosition);

                    // 調用完成回調
                    if (callback) {
                        callback();
                    }

                    resolve();
                })
                .start();
        });
    }

    /**
     * 直線移動動畫（本地座標版本，新版）
     * - 回傳可操作的 tween 與可 await 的 done Promise
     * - 不自動 .start()，由呼叫端決定何時開始
     */
    static MoveToLocalPositionWithTween(
        flyNode: Node,
        startLocalPosition: Vec3,
        endLocalPosition: Vec3,
        duration: number,
        callback?: () => void
    ): { tween: Tween<Node> | null; done: Promise<void> } {
        let resolveDone: () => void;
        const done = new Promise<void>((resolve) => { resolveDone = resolve; });

        if (!flyNode || !flyNode.isValid) {
            console.warn("MoveToLocalPositionWithTween: flyNode is null or invalid");
            if (callback) callback();
            // 立即完成
            resolveDone();
            return { tween: null, done };
        }

        // 設定起始位置
        flyNode.setPosition(startLocalPosition);

        const tw = tween(flyNode)
            .to(duration, { position: endLocalPosition })
            .call(() => {
                flyNode.setPosition(endLocalPosition);
                if (callback) {
                    callback();
                }
                resolveDone();
            });

        return { tween: tw, done };
    }

    /**
     * 貝茲曲線移動動畫（本地座標版本）
     * @param flyNode 要移動的節點
     * @param startLocalPosition 起始本地座標
     * @param endLocalPosition 結束本地座標
     * @param duration 動畫持續時間（秒）
     * @param callback 完成回調函數
     * @returns Promise
     */
    static BezierMoveToLocalPosition(flyNode: Node, startLocalPosition: Vec3, endLocalPosition: Vec3, duration: number, callback?: () => void): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!flyNode || !flyNode.isValid) {
                console.warn("BezierMoveToLocalPosition: flyNode is null or invalid");
                if (callback) callback();
                resolve();
                return;
            }

            // 計算控制點（在起始點和結束點之間的上方創建一個弧形路徑）
            const midX = (startLocalPosition.x + endLocalPosition.x) / 2;
            const midY = (startLocalPosition.y + endLocalPosition.y) / 2;

            // 計算高度偏移：基於起始點和結束點之間的距離
            const distance = Vec3.distance(startLocalPosition, endLocalPosition);
            const heightOffset = Math.max(100, distance * 0.3); // 最小100像素高度

            const controlPoint = new Vec3(midX, midY + heightOffset, 0);

            // 建立貝茲曲線物件（3階貝茲曲線：起始點、控制點、結束點）
            const bezierCurve = new CommonEffect.Bezier([startLocalPosition, controlPoint, endLocalPosition]);

            // 設定起始位置
            flyNode.setPosition(startLocalPosition);

            // 使用臨時物件追蹤動畫進度
            const animationTarget = { progress: 0 };
            tween(animationTarget)
                .to(duration, { progress: 1 }, {
                    onUpdate: (target, ratio) => {
                        // 使用 CommonEffect.Bezier 計算當前位置
                        const currentPos = bezierCurve.GetPosition(ratio);
                        flyNode.setPosition(currentPos);
                    }
                })
                .call(() => {
                    // 確保最終位置正確
                    flyNode.setPosition(endLocalPosition);

                    // 調用完成回調
                    if (callback) {
                        callback();
                    }

                    resolve();
                })
                .start();
        });
    }

    /**
     * 貝茲曲線移動動畫（本地座標版本，新版）
     * - 回傳可操作的 tween 與可 await 的 done Promise
     * - 不自動 .start()，由呼叫端決定何時開始
     */
    static BezierMoveToLocalPositionWithTween(
        flyNode: Node,
        startLocalPosition: Vec3,
        endLocalPosition: Vec3,
        duration: number,
        callback?: () => void
    ): { tween: Tween<{ progress: number }> | null; done: Promise<void> } {
        let resolveDone: () => void;
        const done = new Promise<void>((resolve) => { resolveDone = resolve; });

        if (!flyNode || !flyNode.isValid) {
            console.warn("BezierMoveToLocalPositionWithTween: flyNode is null or invalid");
            if (callback) callback();
            resolveDone();
            return { tween: null, done };
        }

        // 計算控制點（在起始點和結束點之間的上方創建一個弧形路徑）
        const midX = (startLocalPosition.x + endLocalPosition.x) / 2;
        const midY = (startLocalPosition.y + endLocalPosition.y) / 2;

        // 計算高度偏移：基於起始點和結束點之間的距離
        const distance = Vec3.distance(startLocalPosition, endLocalPosition);
        const heightOffset = Math.max(100, distance * 0.3); // 最小100像素高度

        const controlPoint = new Vec3(midX, midY + heightOffset, 0);

        // 建立貝茲曲線物件（3階貝茲曲線：起始點、控制點、結束點）
        const bezierCurve = new CommonEffect.Bezier([startLocalPosition, controlPoint, endLocalPosition]);

        // 設定起始位置
        flyNode.setPosition(startLocalPosition);

        // 使用臨時物件追蹤動畫進度
        const animationTarget = { progress: 0 };
        const tw = tween(animationTarget)
            .to(duration, { progress: 1 }, {
                onUpdate: (target, ratio) => {
                    const currentPos = bezierCurve.GetPosition(ratio);
                    flyNode.setPosition(currentPos);
                }
            })
            .call(() => {
                flyNode.setPosition(endLocalPosition);
                if (callback) {
                    callback();
                }
                resolveDone();
            });

        return { tween: tw, done };
    }

    /**
     * 根據一維位置索引取得行列座標 (各遊戲不同)
     * @param position 一維位置索引 (0-14)
     * @returns {col: number, row: number}
     */
    static GetColRowFromPosition(position: number): { col: number, row: number } {
        if (!this.m_gameView) {
            console.error(`GetColRowFromPosition: GameView is not initialized`);
            return { col: 0, row: 0 };
        }
        return this.m_gameView.SlotReels.GetColRowFromPosition(position);
    }

    /**
     * 根據行列座標取得一維位置索引 (各遊戲不同)
     * @param col 列
     * @param row 行
     * @returns 一維位置索引
     */
    static GetPositionFromColRow(col: number, row: number): number {
        if (!this.m_gameView) {
            console.error(`GetPositionFromColRow: GameView is not initialized`);
            return 0;
        }
        return this.m_gameView.SlotReels.GetPositionFromColRow(col, row);
    }

    /**
	 * 將 IRoundInfo.FeaturePosQueue 轉為有資料的 FeaturePosQueueType 與對應位置們
	 * - 伺服器位置編碼解碼規則：col = floor(n / Game_Define.ROW), row = n % Game_Define.ROW
	 * - 僅輸出有資料的類型
	 * @param featurePosQueue 位置佇列（IRoundInfo.FeaturePosQueue）
	 * @returns 僅包含有資料的型別與位置清單
	 */
	static ParseFeaturePosQueue(
		featurePosQueue: Array<{ Data?: number[] }>
	): Array<{ type: FeaturePosQueueType; positions: Array<{ col: number; row: number }> }>
	{
		const result: Array<{ type: FeaturePosQueueType; positions: Array<{ col: number; row: number }> }> = [];

		if (!featurePosQueue || !Array.isArray(featurePosQueue)) {
			return result;
		}

		for (let typeIndex = 0; typeIndex < featurePosQueue.length; typeIndex++) {
			const queueItem = featurePosQueue[typeIndex];

			// 只處理有 Data 且不為空的項目
			if (!queueItem || !queueItem.Data || queueItem.Data.length === 0) {
				continue;
			}

			// 解碼位置資訊
			const positions: Array<{ col: number; row: number }> = [];
			for (const encodedPos of queueItem.Data) {
                const { col, row } = this.GetColRowFromPosition(encodedPos);
				positions.push({ col, row });
			}

			// 將該類型的資料加入結果
			result.push({
				type: typeIndex as FeaturePosQueueType,
				positions
			});
		}

		return result;
	}

    /**
     * 取得目前語言
     * @returns 目前語言
     */
    static GetLanguage(): string {
        return localeStringManager.CurrLang;
    }

	/**
	 * 解析贏分閾值
	 * @param value 贏分閾值
	 * @returns 贏分閾值，如果無效則返回 null
	 */
	static ParseWinThreshold(value: unknown): number | null {
		const num = Number(value);
		if (!Number.isFinite(num) || num <= 0) {
			return null;
		}
		return num;
	}

	/**
	 * 根據總贏分計算贏分類型
	 * @param totalWin 總贏分
	 * @returns 贏分類型
	 */
	static GetWinType(totalWin: number): WinType {
		if (totalWin <= 0) {
			return WinType.NoWin;
		}

		const config: {
			SUPER_WIN_MIN?: number;
			MEGA_WIN_MIN?: number;
			BIG_WIN_MIN?: number;
			YOU_WIN_MIN?: number;
		} = Game_Define.BigWinWinRule ?? {};
		const superWinMin = this.ParseWinThreshold(config?.SUPER_WIN_MIN);
		const megaWinMin = this.ParseWinThreshold(config?.MEGA_WIN_MIN);
		const bigWinMin = this.ParseWinThreshold(config?.BIG_WIN_MIN);
		const youWinMin = this.ParseWinThreshold(config?.YOU_WIN_MIN) ?? 0;

		if (superWinMin !== null && totalWin >= superWinMin) {
			return WinType.SuperWin;
		}
		if (megaWinMin !== null && totalWin >= megaWinMin) {
			return WinType.MegaWin;
		}
		if (bigWinMin !== null && totalWin >= bigWinMin) {
			return WinType.BigWin;
		}
		if (totalWin >= youWinMin) {
			return WinType.YouWin;
		}
		return WinType.NormalWin;
	}
}

