131	                this.SetMultiplier(multiplierIndex);
132	                resolve();
133	                return;
134	            }
135	            this.m_upgradeSpine.node.active = true;
136	            // 先更新靜態底板到新倍率（閃一下也是正確數字），再隱藏播動畫
137	            this.SetMultiplier(multiplierIndex);
138	            this.SetNodeActive(this.m_baseFrameSpriteChange.node, false);
139	            this.SetNodeActive(this.m_multiplierSpriteChange.node, false);
140	
141	            try {
142	                if (multiplierIndex >= this.m_multiplierSpriteIndexStart) {
143	                    const skinIdx = multiplierIndex - this.m_multiplierSpriteIndexStart;
144	                    if (skinIdx < MultiplierBase.UPGRADE_SKINS.length) {
145	                        this.m_upgradeSpine.setSkin(MultiplierBase.UPGRADE_SKINS[skinIdx]);
146	                    }
147	                } else {
148	                    this.m_upgradeSpine.setSkin('DefaultSkin');
149	                }
150	                this.m_upgradeSpine.setAnimation(0, 'Upgrade', false);
151	            } catch (e) {
152	                this.m_upgradeSpine.node.active = false;
153	                this.SetMultiplier(multiplierIndex);
154	                resolve();
155	                return;
156	            }
157	
158	            let resolved = false;
159	            const done = () => {
160	                if (resolved) return;
161	                resolved = true;
162	                this.m_upgradeSpine.setCompleteListener(null);
163	                this.m_upgradeSpine.node.active = false;
164	                resolve();
165	            };
166	
167	            this.m_upgradeSpine.setCompleteListener(done);
168	            // 靜態底板提前開啟避免銜接斷層
169	            const anim = this.m_upgradeSpine.findAnimation('Upgrade');
170	            const duration = anim ? anim.duration : 0.5;
