import { _decorator, Component, error, log, warn, Node ,UIOpacity, Vec3, tween, Tween, sp, Sprite, Color, instantiate} from 'cc';
import { SpriteChange } from '../Common/SpriteChange';
const { ccclass, property } = _decorator;
import { Common } from '../Common/Common';
import { AudioManager } from '../Audio/AudioManager';

@ccclass('MultiplierBase')
export class MultiplierBase extends Component {
    //#region Properties
    @property({
        type: SpriteChange,
        tooltip: "底框 SpriteChange"
    })
    private m_baseFrameSpriteChange: SpriteChange = null;

    @property({
        type: SpriteChange,
        tooltip: "乘數倍率 SpriteChange"
    })
    private m_multiplierSpriteChange: SpriteChange = null;

    @property({
        type: Sprite,
        tooltip: "倍數底光 Sprite"
    })
    private m_bottomLight: Sprite = null;

    @property({
        type: Node,
        tooltip: "數字 Shadow 節點"
    })
    private m_shadow: Node = null;
    //#endregion Properties

    //#region Variables
    /**@ch 倍率索引*/
    private m_multiplierIndex: number = 0;

    /**@ch 乘數倍率索引開始*/
    private readonly m_multiplierSpriteIndexStart: number = 2;

    @property({
        type: sp.Skeleton,
        tooltip: "升級 Spine 動畫"
    })
    private m_upgradeSpine: sp.Skeleton = null;

    /**@ch 底框倍率限制*/
    private readonly m_baseFrameMultiplierLimits: ReadonlyArray<number> = [2, 5, 8, 11, 16];

    /**@ch 飛行演出用的複用 clone（每個 MultiplierBase 只建一次）*/
    private m_flyClone: Node = null;
    //#endregion Variables

    //#region Lifecycle
    protected onDestroy(): void {
        if (this.m_flyClone && this.m_flyClone.isValid) {
            this.m_flyClone.destroy();
            this.m_flyClone = null;
        }
    }
    //#endregion Lifecycle

    //#region Methods
    /**
     * @ch 設置倍率索引
     * @param multiplierIndex 倍率索引
     */
    public SetMultiplier(multiplierIndex: number) {
        if (!this.m_baseFrameSpriteChange || !this.m_multiplierSpriteChange) {
            error(`[MultiplierBase] 底框或乘數倍率SpriteChange元件未設定`);
            return;
        }
        // 夾制到顯示上限，避免內部索引漂移到可顯示範圍之外
        const maxIndex = this.GetMaxMultiplierIndex();
        if (multiplierIndex > maxIndex) {
            warn(`[MultiplierBase] 倍率索引 ${multiplierIndex} 超過上限 ${maxIndex}，已夾制`);
            multiplierIndex = maxIndex;
        }
        this.m_multiplierIndex = multiplierIndex;

        const showMultiplier = multiplierIndex >= this.m_multiplierSpriteIndexStart;
        const showBaseFrame = multiplierIndex > 0;
        this.SetNodeActive(this.m_baseFrameSpriteChange.node, showBaseFrame);
        this.SetNodeActive(this.m_multiplierSpriteChange.node, showMultiplier);

        this.m_baseFrameSpriteChange.ChangeSpriteByIndex(this.GetBaseFrameIndex(multiplierIndex));
        if (showMultiplier) {
            this.m_multiplierSpriteChange.ChangeSpriteByIndex(multiplierIndex - this.m_multiplierSpriteIndexStart);
        }

        this.UpdateBottomLight(multiplierIndex);
    }

    /**
     * @ch 獲取倍率索引
     * @returns 倍率索引
     */
    public GetMultiplierIndex(): number {
        return this.m_multiplierIndex;
    }

    /**
     * @ch 取得倍率索引上限（可顯示的最大倍率索引）
     * @returns 最大倍率索引；乘數倍率 SpriteChange 未設定時回傳 0
     * @remarks 乘數圖以 (multiplierIndex - m_multiplierSpriteIndexStart) 取圖，故上限 = 圖片數量 + (起始值 - 1)
     */
    public GetMaxMultiplierIndex(): number {
        if (!this.m_multiplierSpriteChange) return 0;
        return this.m_multiplierSpriteChange.GetSpriteFrameCount() + this.m_multiplierSpriteIndexStart - 1;
    }

    /**@ch Spine skin 名稱對應表（index 0 = multiplierIndex 2）*/
    private static readonly UPGRADE_SKINS: ReadonlyArray<string> = [
        '2', '4', '8', '16', '32', '64', '128', '256', '512', '1024', '2048', '4096', '8192', '9999'
    ];

    /**@ch 底光顏色常量（tier1 = x2~x8 ... tier4 = x1024~x9999）*/
    private static readonly BOTTOM_LIGHT_COLOR_TIER1 = new Color(122, 0, 2, 255);
    private static readonly BOTTOM_LIGHT_COLOR_TIER2 = new Color(0, 58, 207, 255);
    private static readonly BOTTOM_LIGHT_COLOR_TIER3 = new Color(0, 115, 109, 255);
    private static readonly BOTTOM_LIGHT_COLOR_TIER4 = new Color(255, 105, 0, 255);

    /**
     * @ch 播放升級動畫後再設置倍率
     * @param multiplierIndex 新的倍率索引
     */
    public PlayUpgradeAndSetMultiplier(multiplierIndex: number): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!this.m_upgradeSpine || !this.m_upgradeSpine.skeletonData || multiplierIndex < this.m_multiplierIndex) {
                this.SetMultiplier(multiplierIndex);
                resolve();
                return;
            }
            this.m_upgradeSpine.node.active = true;
            // 先更新靜態底板到新倍率（閃一下也是正確數字），再隱藏播動畫
            this.SetMultiplier(multiplierIndex);
            this.SetNodeActive(this.m_baseFrameSpriteChange.node, false);
            this.SetNodeActive(this.m_multiplierSpriteChange.node, false);

            try {
                if (multiplierIndex >= this.m_multiplierSpriteIndexStart) {
                    const skinIdx = multiplierIndex - this.m_multiplierSpriteIndexStart;
                    if (skinIdx < MultiplierBase.UPGRADE_SKINS.length) {
                        this.m_upgradeSpine.setSkin(MultiplierBase.UPGRADE_SKINS[skinIdx]);
                    }
                } else {
                    this.m_upgradeSpine.setSkin('DefaultSkin');
                }
                this.m_upgradeSpine.setAnimation(0, 'Upgrade', false);
            } catch (e) {
                this.m_upgradeSpine.node.active = false;
                this.SetMultiplier(multiplierIndex);
                resolve();
                return;
            }

            let resolved = false;
            const done = () => {
                if (resolved) return;
                resolved = true;
                this.m_upgradeSpine.setCompleteListener(null);
                this.m_upgradeSpine.node.active = false;
                resolve();
            };

            this.m_upgradeSpine.setCompleteListener(done);
            // 靜態底板提前開啟避免銜接斷層
            const anim = this.m_upgradeSpine.findAnimation('Upgrade');
            const duration = anim ? anim.duration : 0.5;
            const showBaseFrame = multiplierIndex > 0;
            const showMultiplier = multiplierIndex >= this.m_multiplierSpriteIndexStart;
            this.scheduleOnce(() => {
                this.SetNodeActive(this.m_baseFrameSpriteChange.node, showBaseFrame);
                this.SetNodeActive(this.m_multiplierSpriteChange.node, showMultiplier);
            }, Math.max(duration - 0.1, 0));
            // fallback：確保不會卡住
            this.scheduleOnce(done, duration + 0.05);
        });
    }

    /**
     * @ch 更新倍數底光的縮放與顏色
     * @param multiplierIndex 倍率索引
     */
    private UpdateBottomLight(multiplierIndex: number): void {
        if (!this.m_bottomLight || !this.m_bottomLight.node) return;

        // multiplierIndex: 0~1=不顯示, 2~4=x2~x8, 5~7=x16~x64, 8~10=x128~x512, 11+=x1024~x9999
        if (multiplierIndex < 2) {
            this.m_bottomLight.node.active = false;
            return;
        }

        this.m_bottomLight.node.active = true;
        let scaleX: number;
        let color: Color;

        if (multiplierIndex >= 11) {
            // x1024~x9999
            scaleX = 2;
            color = MultiplierBase.BOTTOM_LIGHT_COLOR_TIER4;
        } else if (multiplierIndex >= 8) {
            // x128~x512
            scaleX = 1.8;
            color = MultiplierBase.BOTTOM_LIGHT_COLOR_TIER3;
        } else if (multiplierIndex >= 5) {
            // x16~x64
            scaleX = 1.5;
            color = MultiplierBase.BOTTOM_LIGHT_COLOR_TIER2;
        } else {
            // x2~x8
            scaleX = 1.2;
            color = MultiplierBase.BOTTOM_LIGHT_COLOR_TIER1;
        }

        this.m_bottomLight.node.setScale(scaleX, 1, 1);
        this.m_bottomLight.color = color;
    }

    /**
     * @ch 獲取底框索引
     * @param multiplierIndex 倍率索引
     * @returns 底框索引
     */
    private GetBaseFrameIndex(multiplierIndex: number): number {
        if (this.m_baseFrameMultiplierLimits.length === 0) {
            return 0;
        }
        for (let i = 0; i < this.m_baseFrameMultiplierLimits.length; i++) {
            if (multiplierIndex < this.m_baseFrameMultiplierLimits[i]) {
                return i;
            }
        }
        return this.m_baseFrameMultiplierLimits.length - 1;
    }

    /**
     * @ch 設置節點顯示狀態
     * @param node 節點
     * @param isActive 顯示狀態
     */
    private SetNodeActive( node: Node, isActive: boolean) {
        if (node && node.isValid) {
            node.active = isActive;
        }
    }

    /**
     * @ch 設置底框顯示狀態
     * @param isShow 顯示狀態
     */
    public SetFrameShow(isShow: boolean) {
        this.SetNodeActive(this.m_baseFrameSpriteChange.node, isShow);
    }

    /**
     * @ch 設置乘數倍率顯示狀態
     * @param isShow 顯示狀態
     */
    public SetMultiplierShow(isShow: boolean) {
        this.SetNodeActive(this.m_multiplierSpriteChange.node, isShow);
    }

    public SetMultiplierNodeToOtherLayer(parent: Node) {
        // 0 階（倍率未啟動）不抬數字
        if (this.m_multiplierIndex < this.m_multiplierSpriteIndexStart) return;

        if (this.m_shadow) {
            const wp = this.m_shadow.getWorldPosition();
            this.m_shadow.setParent(parent, true);
            this.m_shadow.setWorldPosition(wp);
            let opacity = this.m_shadow.getComponent(UIOpacity);
            if (!opacity) { opacity = this.m_shadow.addComponent(UIOpacity); }
            opacity.opacity = 200;
        }
        this.m_multiplierSpriteChange.node.active = true;
        Tween.stopAllByTarget(this.m_multiplierSpriteChange.node);
        this.m_multiplierSpriteChange.node.setParent(parent,true);
        this.m_multiplierSpriteChange.node.getComponent(UIOpacity).opacity = 255;
        if (this.m_upgradeSpine) {
            const wp = this.m_upgradeSpine.node.getWorldPosition();
            this.m_upgradeSpine.node.setParent(parent, true);
            this.m_upgradeSpine.node.setWorldPosition(wp);
        }
    }

    public RecoverMultiplierNode(): void {
        // 0 階沒有抬起，不需要恢復
        if (this.m_multiplierIndex < this.m_multiplierSpriteIndexStart) return;

        // 停掉飛行中的 clone
        if (this.m_flyClone && this.m_flyClone.isValid) {
            Tween.stopAllByTarget(this.m_flyClone);
            const cloneOpacity = this.m_flyClone.getComponent(UIOpacity);
            if (cloneOpacity) Tween.stopAllByTarget(cloneOpacity);
            this.m_flyClone.active = false;
        }

        if (this.m_shadow) {
            this.m_shadow.setParent(this.node, false);
            this.m_shadow.setPosition(0, 0, 0);
            let opacity = this.m_shadow.getComponent(UIOpacity);
            if (opacity) opacity.opacity = 255;
        }
        this.m_multiplierSpriteChange.node.active = false;
        this.m_multiplierSpriteChange.node.setParent(this.node,false);
        this.m_multiplierSpriteChange.node.setScale(0.8069, 0.8069, 0.8069);
        this.m_multiplierSpriteChange.node.setPosition(0,0,0);
        this.m_multiplierSpriteChange.node.getComponent(UIOpacity).opacity = 80;
        if (this.m_upgradeSpine) {
            this.m_upgradeSpine.node.setParent(this.node, false);
            this.m_upgradeSpine.node.setPosition(0, 0, 0);
        }
    }

    /** @ch GC 優化：飛行目標位置復用（每個 instance 各自一份，不會並行衝突） */
    private _flyTargetVec3 = new Vec3();

    public MulItemFlyToTarget(targetPos: Vec3, duration: number, callback: () => void): void {
        this._flyTargetVec3.set(targetPos.x + 15, targetPos.y - 15, targetPos.z);
        const adjustedTarget = this._flyTargetVec3;

        if (this.m_multiplierIndex >= this.m_multiplierSpriteIndexStart) {
            // 懶建立飛行 clone（每個 MultiplierBase 只建一次，重複使用不 destroy）
            if (!this.m_flyClone || !this.m_flyClone.isValid) {
                this.m_flyClone = instantiate(this.m_multiplierSpriteChange.node);
            }
            const clone = this.m_flyClone;

            // 同步當前倍率的 sprite frame
            const srcSprite = this.m_multiplierSpriteChange.node.getComponent(Sprite);
            const dstSprite = clone.getComponent(Sprite);
            if (srcSprite && dstSprite) dstSprite.spriteFrame = srcSprite.spriteFrame;

            clone.setParent(this.m_multiplierSpriteChange.node.parent);
            clone.setWorldPosition(this.m_multiplierSpriteChange.node.getWorldPosition());
            clone.active = true;

            Tween.stopAllByTarget(clone);
            let opacity = clone.getComponent(UIOpacity);
            if (!opacity) { opacity = clone.addComponent(UIOpacity); }
            opacity.opacity = 255;
            Tween.stopAllByTarget(opacity);

            tween(clone)
                .to(duration, { worldPosition: adjustedTarget }, { easing: 'cubicOut' })
                .call(() => {
                    clone.active = false;
                    if (callback) callback();
                })
                .start();
        } else {
            if (callback) callback();
        }
    }
    //#endregion Methods
}

