271	    /**
272	     * @ch 事件回調
273	     * @param event 事件名稱
274	     * @param args 事件參數
275	     */
276	    OnEvent(event: string, ...args: any[]) {
277	        switch (event) {
278	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER:
279	                if (this.ValidateSetMultiplierArgs(args)) {
280	                    this.SetMultiplier(args[0] as number, args[1] as number);
281	                }
282	                break;
283	
284	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM:
285	                this.SetMultiplierWithAnim(args[0] as number, args[1] as number, args[2] as () => void);
286	                break;
287	                
288	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_LIST:
289	                if (this.ValidateSetMultiplierListArgs(args)) {
290	                    this.SetMultiplierList(args[0] as number[]);
291	                }
292	                break;
293	
294	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW:
295	                if (this.ValidateSetShowArgs(args)) {
296	                    this.SetShow(args[0] as number, args[1] as boolean);
297	                }
298	                break;
299	
300	            case MULTIPLIER_BASE_MANAGER_EVENT.SET_FRAME_SHOW:
301	                if (this.ValidateSetFrameShowArgs(args)) {
302	                    this.SetFrameShow(args[0] as number, args[1] as boolean);
303	                }
304	                break;
305	            case MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM:
306	                if (this.ValidatePopMulItemArgs(args)) {
307	                    this.PopMulItem(args[0] as number, args[1] as Node);
308	                }
309	                break;
310	            case MULTIPLIER_BASE_MANAGER_EVENT.PUSH_MULITEM:
311	                if (this.ValidatePushMulItemArgs(args)) {
312	                    this.PushMulItem(args[0] as number);
313	                }
314	                break;
315	            case MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET:
316	                if (this.ValidateMulItemFlyToTargetArgs(args)) {
317	                    this.MulItemFlyToTarget(args[0] as number, args[1] as Vec3, args[2] as number, args[3] as () => void);
318	                }
319	                break;
320	            case MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER:
321	                if (this.ValidateAddMultiplierArgs(args)) {
322	                    this.AddMultiplier(args[0] as number);
323	                }
324	                break;
325	            case MULTIPLIER_BASE_MANAGER_EVENT.ADD_MULTIPLIER_WITH_ANIM:
326	                if (this.ValidateAddMultiplierArgs(args)) {
327	                    this.AddMultiplierWithAnim(args[0] as number, args[1] as number, args[2] as () => void);
328	                }
329	                break;
330	            case MULTIPLIER_BASE_MANAGER_EVENT.CHECK_MULTIPLIER_WITH_SERVER:
331	                this.CheckMultiplierWithServer(
332	                    args[0] as protocol.ar2pq9Proto.IIntAry[],
333	                    args[1] as number[]
334	                );
335	                break;
336	            default:
337	                warn('[MultiplierBaseManager] OnEvent: 未知的事件', event);
338	        }
339	    }
