543	    /**
544	     * @ch 指定索引的倍率加 1（index 為負數時設置全部）
545	     * 已達最大倍數時保持最高倍數不變
546	     * @param index 目標 MultiplierBase 索引，負數表示全部
547	     */
548	    private AddMultiplier(index: number): void {
549	        if (index < 0) {
550	            this.AddAllMultiplier();
551	            return;
552	        }
553	        const item = this.GetMultiplierBase(index);
554	        if (!item) return;
555	        if (this.IsAtMaxMultiplier(item)) {
556	            item.SetMultiplier(item.GetMaxMultiplierIndex());
557	            return;
558	        }
559	        item.SetMultiplier(item.GetMultiplierIndex() + 1);
560	    }
