562	    /**
563	     * @ch 所有 MultiplierBase 的倍率加 1
564	     * 已達最大倍數時保持最高倍數不變
565	     */
566	    private AddAllMultiplier(): void {
567	        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
568	            warn('[MultiplierBaseManager] AddAllMultiplier: MultiplierBase 陣列未設置');
569	            return;
570	        }
571	        this.m_multiplierBases.forEach((item, i) => {
572	            if (!item) {
573	                warn(`[MultiplierBaseManager] AddAllMultiplier: 索引 ${i} 的 MultiplierBase 未設置`);
574	                return;
575	            }
576	            if (this.IsAtMaxMultiplier(item)) {
577	                item.SetMultiplier(item.GetMaxMultiplierIndex());
578	                return;
579	            }
580	            item.SetMultiplier(item.GetMultiplierIndex() + 1);
581	        });
582	    }
583	
584	    /**
585	     * @ch 播放加成動畫後指定索引的倍率加 amount 階（index 為負數時設置全部）
586	     * 已達最大倍數時仍播放升級動畫，倍數保持最高
587	     * @param index 目標 MultiplierBase 索引，負數表示全部
588	     * @param amount 一次加幾階（標靶∩標靶重疊位置 > 1；預設 1，非正數一律視為 1）
589	     * @param callback 動畫完成後的回調函數
590	     */
591	    private AddMultiplierWithAnim(index: number, amount: number = 1, callback?: () => void): void {
592	        const step = (typeof amount === 'number' && amount > 0) ? Math.floor(amount) : 1;
593	        if (index < 0) {
594	            this.AddAllMultiplierWithAnim(step, callback);
595	            return;
596	        }
597	        const item = this.GetMultiplierBase(index);
598	        if (!item) { if (callback) callback(); return; }
599	        // 已達最大倍數時仍播升級動畫，保持在最高倍數
600	        const target = Math.min(item.GetMultiplierIndex() + step, item.GetMaxMultiplierIndex());
601	        item.PlayUpgradeAndSetMultiplier(target).then(() => {
602	            if (callback) callback();
603	        });
604	    }
605	
606	    /**
607	     * @ch 播放加成動畫後所有 MultiplierBase 的倍率加 step 階
608	     * 已達最大倍數時仍播放升級動畫，倍數保持最高
609	     * @param step 一次加幾階（預設 1）
610	     * @param callback 全部動畫完成後的回調函數
611	     */
612	    private AddAllMultiplierWithAnim(step: number = 1, callback?: () => void): void {
613	        if (!this.m_multiplierBases || this.m_multiplierBases.length === 0) {
614	            warn('[MultiplierBaseManager] AddAllMultiplierWithAnim: MultiplierBase 陣列未設置');
615	            if (callback) callback();
616	            return;
617	        }
618	        const promises: Promise<void>[] = [];
619	        this.m_multiplierBases.forEach((item, i) => {
620	            if (!item) {
621	                warn(`[MultiplierBaseManager] AddAllMultiplierWithAnim: 索引 ${i} 的 MultiplierBase 未設置`);
622	                return;
623	            }
624	            // 已達最大倍數時仍播升級動畫，保持在最高倍數
625	            const target = Math.min(item.GetMultiplierIndex() + step, item.GetMaxMultiplierIndex());
626	            promises.push(item.PlayUpgradeAndSetMultiplier(target));
627	        });
628	        Promise.all(promises).then(() => {
629	            if (callback) callback();
630	        });
631	    }
632	
633	    /**
634	     * @ch 回歸守衛：驗證被消除位置的乘倍底板當前 index 是否等於 Server 期望（BasePlateIndex）
635	     * 位置 index = col*ROW+row 對應 m_multiplierBases。Server 值會先夾到顯示上限再比對，
636	     * 避免高倍率被 clamp（SetMultiplier 內）造成假警報。不一致只 error log，不影響玩法
637	     * （同 SlotReels.CheckPlateInfo 風格）。
638	     * @param basePlateIndex Server 每位置底板絕對 index（[col].Data[row]）
639	     * @param positions 本盤被消除的位置（一維索引）
640	     */
641	    private CheckMultiplierWithServer(
642	        basePlateIndex: protocol.ar2pq9Proto.IIntAry[],
643	        positions: number[]
644	    ): void {
645	        if (!basePlateIndex || basePlateIndex.length === 0) return;
646	        if (!positions || positions.length === 0) return;
647	
648	        const errors: any[] = [];
649	        for (const pos of positions) {
650	            if (pos < 0 || pos >= this.m_multiplierBases.length) continue;
651	            const item = this.m_multiplierBases[pos];
652	            if (!item) continue;
653	
654	            const col = Math.floor(pos / Game_Define.ROW);
655	            const row = pos % Game_Define.ROW;
656	            const expected = basePlateIndex[col]?.Data?.[row];
657	            if (expected === null || expected === undefined) continue;
658	
659	            // Server 值夾到顯示上限再比（顯示本就 clamp，超限非錯誤）
660	            const expectedClamped = Math.min(expected, item.GetMaxMultiplierIndex());
661	            const actual = item.GetMultiplierIndex();
662	            if (actual !== expectedClamped) {
663	                errors.push({ pos, col, row, expected, expectedClamped, actual });
664	            }
665	        }
666	
667	        if (errors.length > 0) {
668	            error('[MultiplierBaseManager] 乘倍底板與 Server 期望值不一致:', JSON.stringify(errors));
669	        }
670	    }
671	    //#endregion Methods
672	
673	    //#region 測試功能
674	    /**
675	     * @ch 測試按鍵處理
676	     * - 數字鍵 1：設置索引 0 的倍率為 3
677	     * - 數字鍵 2：設置索引 0 的倍率為 6
678	     * - 數字鍵 3：設置所有倍率為 5
679	     * - 數字鍵 4：隱藏索引 0
680	     * - 數字鍵 5：顯示索引 0
681	     * - 數字鍵 6：批次設置倍率 [2, 5, 8]
682	     */
683	    private CheckTestKeyCode(event: EventKeyboard): void {
684	        switch (event.keyCode) {
685	            case KeyCode.DIGIT_1:
686	
687	                this.SetMultiplier(0, 3);
688	                break;
689	
690	            case KeyCode.DIGIT_2:
691	
692	                this.SetMultiplier(0, 6);
693	                break;
694	
695	            case KeyCode.DIGIT_3:
696	
697	                this.SetMultiplier(-1, 5);
698	                break;
699	
700	            case KeyCode.DIGIT_4:
701	
702	                this.SetShow(0, false);
703	                break;
704	
705	            case KeyCode.DIGIT_5:
706	
707	                this.SetShow(0, true);
708	                break;
709	
710	            case KeyCode.DIGIT_6:
711	
712	                this.SetMultiplierList([2, 5, 8]);
713	                break;
714	        }
715	    }
716	    //#endregion 測試功能
717	}
