import { eventManager } from 'db://astarte-framework/Managers';
import { AwardUIEventName } from '../Game_Define';
import { Define } from 'db://astarte-framework/utilis';

/**
 * 獎勵UI工具類別
 * @description 提供靜態方法來觸發AwardUIController的事件，簡化使用流程
 */
export class AwardUIHelper {
    /**
     * 顯示黑張
     * @description 觸發顯示黑張事件，會通知AwardUIController執行ShowBlackMask
     * @example
     * ```typescript
     * AwardUIHelper.ShowBlackMask();
     * ```
     */
    public static ShowBlackMask(): void {
        eventManager.Dispatch(AwardUIEventName.SHOW_BLACK_MASK);
    }

    /**
     * 隱藏黑張
     * @description 觸發隱藏黑張事件，會通知AwardUIController執行HideBlackMask
     * @example
     * ```typescript
     * AwardUIHelper.HideBlackMask();
     * ```
     */
    public static HideBlackMask(): void {
        eventManager.Dispatch(AwardUIEventName.HIDE_BLACK_MASK);
    }

    /**
     * 延遲顯示黑張
     * @param delayTime 延遲時間（秒）
     * @param component 組件參數，用於 Define.Wait
     * @description 在指定時間後顯示黑張
     * @example
     * ```typescript
     * AwardUIHelper.DelayShowBlackMask(2.0, this); // 2秒後顯示黑張
     * ```
     */
    public static async DelayShowBlackMask(delayTime: number, component: any): Promise<void> {
        await Define.Wait(component, delayTime);
        eventManager.Dispatch(AwardUIEventName.SHOW_BLACK_MASK);
    }

    /**
     * 延遲隱藏黑張
     * @param delayTime 延遲時間（秒）
     * @param component 組件參數，用於 Define.Wait
     * @description 在指定時間後隱藏黑張
     * @example
     * ```typescript
     * AwardUIHelper.DelayHideBlackMask(3.0, this); // 3秒後隱藏黑張
     * ```
     */
    public static async DelayHideBlackMask(delayTime: number, component: any): Promise<void> {
        await Define.Wait(component, delayTime);
        eventManager.Dispatch(AwardUIEventName.HIDE_BLACK_MASK);
    }

    /**
     * 自動顯示隱藏黑張
     * @param showTime 顯示持續時間（秒）
     * @param component 組件參數，用於 Define.Wait
     * @description 立即顯示黑張，並在指定時間後自動隱藏
     * @example
     * ```typescript
     * AwardUIHelper.AutoShowHideBlackMask(2.5, this); // 顯示2.5秒後自動隱藏
     * ```
     */
    public static async AutoShowHideBlackMask(showTime: number, component: any): Promise<void> {
        // 立即顯示黑張
        eventManager.Dispatch(AwardUIEventName.SHOW_BLACK_MASK);

        // 指定時間後自動隱藏
        await Define.Wait(component, showTime);
        eventManager.Dispatch(AwardUIEventName.HIDE_BLACK_MASK);
    }

    /**
     * 狀態切換（如果需要記錄狀態）
     * @description 切換黑張的顯示/隱藏狀態
     * @example
     * ```typescript
     * AwardUIHelper.ToggleBlackMask(); // 切換黑張狀態
     * ```
     */
    private static isBlackMaskShowing: boolean = false;

    public static ToggleBlackMask(): void {
        if (this.isBlackMaskShowing) {
            this.HideBlackMask();
            this.isBlackMaskShowing = false;
        } else {
            this.ShowBlackMask();
            this.isBlackMaskShowing = true;
        }
    }

    /**
     * 重置狀態
     * @description 重置內部狀態追蹤，通常在場景切換時使用
     */
    public static ResetState(): void {
        this.isBlackMaskShowing = false;
    }

    /**
     * 獲取當前狀態
     * @returns 當前黑張是否顯示中
     * @description 返回黑張的顯示狀態（僅供參考，實際狀態由AwardUIController管理）
     */
    public static GetIsShowing(): boolean {
        return this.isBlackMaskShowing;
    }
}

