import {_decorator, Component} from 'cc';
const {ccclass, property} = _decorator;

import {NumberAnimation} from '../Common/NumberAnimation';

@ccclass('WinEffectCtrl')
export class WinEffectCtrl extends Component {
  @property({type: NumberAnimation, displayName: '數字動畫組件'})
  protected m_WinLabel: NumberAnimation = null;

  protected m_FinishCallback: Function = null;

  /**@en Initialization flag @ch 初始化標記 */
  private m_IsInitialized: boolean = false;

  /**@en Load component @ch 載入組件 */
  public onLoad() {
    this.Initialize();
  }

  /**@en Initialize component @ch 初始化組件 */
  private Initialize(): void {
    if (this.m_IsInitialized)
      return; // 避免重複初始化

    this.m_IsInitialized = true;
    if (this.m_WinLabel !== null && this.m_WinLabel.FinishDelegate !== null) {
      this.m_WinLabel.FinishDelegate.insert(this.StopEffect, this);
    }
  }

  /**@en Destroy component @ch 銷毀組件 */
  public onDestroy() {
    if (this.m_WinLabel !== null && this.m_WinLabel.FinishDelegate !== null) {
      this.m_WinLabel.FinishDelegate.remove(this.StopEffect, this);
    }
  }

  /**@en Force skip effect @ch 強制跳過報獎效果 */
  public ForceSkipEffect(): void {
    if (this.m_WinLabel !== undefined) {
      this.m_WinLabel.StopAndJumpToTarget();
    }
  }

  /**@en Play effect @ch 播放報獎效果 */
  public PlayEffect(
    winNum: number,
    finishTime: number,
    callback?: Function,
    target?
  ): void {
    this.Initialize();

    if (callback !== null) this.m_FinishCallback = callback.bind(target);
    this.PlayNumberAnimation(winNum, finishTime);
  }

  /**
   * @ch 播放數字動畫（子類可覆寫）
   */
  protected PlayNumberAnimation(winNum: number, finishTime: number): void {
    if (this.m_WinLabel !== null) {
      this.m_WinLabel.Reset();
      this.m_WinLabel.PlayRolling(0, winNum, finishTime);
    } else {
      this.scheduleOnce(this.StopEffect, finishTime);
    }
  }

  /**@en Stop effect @ch 停止報獎效果 */
  public StopEffect(): void {
    this.unschedule(this.StopEffect);
    if (this.m_FinishCallback !== null) {
      this.m_FinishCallback();
    }
  }
}

