import { _decorator, Button, Component, log, Node, tween } from 'cc';
import { setOpacity, getUIOpacity } from '../Common/NodeProperty';
import { eventManager } from 'db://astarte-framework/Managers';
import { AwardUIEventName } from '../Game_Define';

const { ccclass, property } = _decorator;

@ccclass('AwardUIController')
export class AwardUIController extends Component {
    @property( {
        type: Node,
        displayName: "黑張"
    } )
    private m_blackMask: Node = null;
    public get BlackMask(): Node
    {
        return this.m_blackMask;
    }

    @property( {
        type: Node,
        displayName: "透明黑遮罩"
    } )
    private m_transparentBlackMask: Node = null;

    private m_transparentBlackMaskButton: Button = null;
    private m_transparentBlackMaskTouchCallback: (() => void) | null = null;

    onLoad()
    {
        this.m_blackMask.active = false;
        this.m_transparentBlackMask.active = false;
        this.m_transparentBlackMaskButton = this.m_transparentBlackMask.getComponent(Button);

        if (this.m_transparentBlackMaskButton) {
            this.m_transparentBlackMaskButton.node.on(Button.EventType.CLICK, this.OnTransparentBlackMaskClicked, this);
        } else if (this.m_transparentBlackMask) {
            // fallback：若 prefab 沒掛 Button，至少仍能接到點擊（需確保有 UITransform）
            this.m_transparentBlackMask.on(Node.EventType.TOUCH_END, this.OnTransparentBlackMaskClicked, this);
        }

        // 註冊事件監聽
        eventManager.Register(AwardUIEventName.SHOW_BLACK_MASK, this);
        eventManager.Register(AwardUIEventName.HIDE_BLACK_MASK, this);
        eventManager.Register(AwardUIEventName.SHOW_TRANSPARENT_BLACK_MASK, this);
        eventManager.Register(AwardUIEventName.HIDE_TRANSPARENT_BLACK_MASK, this);
    }

    onDestroy()
    {
        if (this.m_transparentBlackMaskButton) {
            this.m_transparentBlackMaskButton.node.off(Button.EventType.CLICK, this.OnTransparentBlackMaskClicked, this);
        } else if (this.m_transparentBlackMask) {
            this.m_transparentBlackMask.off(Node.EventType.TOUCH_END, this.OnTransparentBlackMaskClicked, this);
        }

        // 清理事件監聽
        eventManager.UnRegister(AwardUIEventName.SHOW_BLACK_MASK, this);
        eventManager.UnRegister(AwardUIEventName.HIDE_BLACK_MASK, this);
        eventManager.UnRegister(AwardUIEventName.SHOW_TRANSPARENT_BLACK_MASK, this);
        eventManager.UnRegister(AwardUIEventName.HIDE_TRANSPARENT_BLACK_MASK, this);
    }

    /**
     * @ch 驗證事件名稱
     * @param event 事件名稱
     * @returns 是否有效
     */
    private ValidateEventName(event: string): boolean
    {
        if (!event || typeof event !== 'string') {
            console.warn('[AwardUIController] OnEvent: 無效的事件名稱', event);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 SHOW_TRANSPARENT_BLACK_MASK 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateShowTransparentBlackMaskArgs(args: any[]): boolean
    {
        if (args.length > 0 && typeof args[0] !== 'function') {
            console.warn('[AwardUIController] SHOW_TRANSPARENT_BLACK_MASK: 無效的回調函數參數', args[0]);
            return false;
        }
        return true;
    }

    /**
     * @ch 事件處理方法
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[])
    {
        if (!this.ValidateEventName(event)) {
            return;
        }

        switch (event)
        {
            case AwardUIEventName.SHOW_BLACK_MASK:
                this.ShowBlackMask();
                break;
            case AwardUIEventName.HIDE_BLACK_MASK:
                this.HideBlackMask();
                break;
            case AwardUIEventName.SHOW_TRANSPARENT_BLACK_MASK:
                if (this.ValidateShowTransparentBlackMaskArgs(args)) {
                    this.ShowTransparentBlackMask(args[0]);
                }
                break;
            case AwardUIEventName.HIDE_TRANSPARENT_BLACK_MASK:
                this.HideTransparentBlackMask();
                break;
        }
    }

    /**
     * @ch 顯示黑張
     */
    private ShowBlackMask()
    {
        if (this.m_blackMask) {
            if (!this.m_blackMask.active)
                this.m_blackMask.active = true;

            // 淡入
            setOpacity(this.m_blackMask, 0);
            tween(getUIOpacity(this.m_blackMask)).to(0.5, { opacity: 204 }).start();
        }
    }

    /**
     * @ch 隱藏黑張
     */
    private HideBlackMask()
    {
        if (this.m_blackMask) {
            setOpacity(this.m_blackMask, 0);
            this.m_blackMask.active = false;
        }
    }

    /**
     * @ch 顯示透明黑遮罩
     * @param touchCallback 點擊遮罩的 callback
     */
    private ShowTransparentBlackMask(touchCallback?: () => void)
    {
        this.m_transparentBlackMaskTouchCallback = touchCallback ?? null;
        this.m_transparentBlackMask.active = true;
    }

    /**
     * @ch 點擊透明黑遮罩的 callback
     */
    private OnTransparentBlackMaskClicked()
    {
        log("OnTransparentBlackMaskClicked");

        this.m_transparentBlackMaskTouchCallback?.();
    }

    /**
     * @ch 隱藏透明黑遮罩
     */
    private HideTransparentBlackMask()
    {
        this.m_transparentBlackMask.active = false;
        this.m_transparentBlackMaskTouchCallback = null;
    }
}
